 /* 客服工作台 */
 const ViewWorkbench = {
   setup(){
     const msgFlowRef = ref(null)
     watch(()=>activeConv.value?.msgs?.length, async ()=>{
       await nextTick()
       if(msgFlowRef.value) msgFlowRef.value.scrollTop = msgFlowRef.value.scrollHeight
     })
     const pickConv = (c)=>{
       ui.activeConvId = c.id
       c.unread = 0
       ui.aiSuggest = ''
       nextTick(()=>{
         if(msgFlowRef.value) msgFlowRef.value.scrollTop = msgFlowRef.value.scrollHeight
       })
     }
     const useAI = ()=>{
       ui.reply = ui.aiSuggest
       ui.aiSuggest = ''
     }
     const send = ()=>ops.sendReply(ui.reply)
     const pickTemplate = (t)=>{ ui.reply = t }
     const meInfo = computed(()=>({
       diamonds: store.diamonds || 0,
       cash: typeof store.cash === 'number' ? store.cash : 0,
       vip: !!store.user?.vip,
       authed: !!store.isAuthed,
     }))
     return {store, ui, ops, fakeConvs, activeConv, activeFake, pickConv, useAI, send, pickTemplate, meInfo, msgFlowRef, findUser, totalUnread}
   },
   template:`<div class="cs-layout">
     <!-- 左：会话列表 -->
     <div class="cs-col">
       <div class="cs-col-head">
         <span>待回复会话 <span v-if="totalUnread" class="tag red">{{totalUnread}}</span></span>
         <span class="tag">{{fakeConvs.length}}</span>
       </div>
       <div class="cs-col-body">
         <div v-if="!fakeConvs.length" class="empty"><div class="ei">📭</div><div>暂无会话<br><small>男用户和假用户开始聊天后会出现在此</small></div></div>
         <div v-for="c in fakeConvs" :key="c.id" class="conv-item" :class="{active:ui.activeConvId===c.id}" @click="pickConv(c)">
           <div class="av" :class="'av-'+(findUser(c.uid)?.av||1)">{{findUser(c.uid)?.name?.[0]||'?'}}</div>
           <div class="iv">
             <div class="nm">
               <span class="n">{{findUser(c.uid)?.name}}</span>
               <span class="t">{{c.time}}</span>
             </div>
             <div class="ln">{{c.lastMsg||'(无消息)'}}</div>
             <div class="as">扮演 → 男用户 #{{store.user.id}}</div>
           </div>
           <div v-if="c.unread" class="bd">{{c.unread}}</div>
         </div>
       </div>
     </div>

     <!-- 中：聊天上下文 -->
     <div class="cs-col cs-chat">
       <template v-if="activeConv && activeFake">
         <div class="cs-chat-head">
           <div class="av" :class="'av-'+(activeFake.av||1)">{{activeFake.name?.[0]||'?'}}</div>
           <div class="iv">
             <div class="n">扮演 {{activeFake.name}}（假身份）</div>
             <div class="m">对话男用户：{{store.user.name}} · 钻石 {{store.diamonds}} · {{store.user.vip?'VIP':'普通'}}</div>
           </div>
           <span class="tag green" v-if="activeFake.online">● 在线</span>
         </div>
         <div class="cs-msg-flow" ref="msgFlowRef">
           <template v-for="(m,i) in activeConv.msgs" :key="i">
             <div v-if="m.type==='sys'" class="cs-sys">{{m.text}}</div>
             <div v-else-if="m.type==='out'" class="cs-bubble-row">
               <div class="av" :class="'av-'+store.user.av">{{store.user.name?.[0]||'?'}}</div>
               <div>
                 <div class="cs-bubble">{{m.text}}</div>
                 <div class="meta">男用户 · {{m.time}}{{m.cost?' · -'+m.cost+'💎':''}}</div>
               </div>
             </div>
             <div v-else-if="m.type==='in'" class="cs-bubble-row fake">
               <div class="av" :class="'av-'+(activeFake.av||1)">{{activeFake.name?.[0]||'?'}}</div>
               <div>
                 <div class="cs-bubble">{{m.text}}</div>
                 <div class="meta" style="text-align:right;">{{m.cs?'客服回复':'系统推送'}} · {{m.time}}</div>
