               <div class="av" :class="'av-'+store.user.av">{{store.user.name?.[0]||'?'}}</div>
               <div>
                 <div class="cs-bubble" style="background:linear-gradient(135deg,#fff5d6,#ffe8b3);color:#5a3a00;">{{m.from==='me'?'对方送出 ':'我送出 '}}{{m.em}} {{m.text}} <small>({{m.price}}💎)</small></div>
