             </div>
           </template>
         </div>
         <div class="cs-input-bar">
           <div class="cs-input-row">
             <textarea v-model="ui.reply" :placeholder="'作为 '+activeFake.name+' 回复对方...'" @keydown.ctrl.enter="send"></textarea>
             <div style="display:flex;flex-direction:column;gap:6px;">
