     <!-- 右：男用户画像 + AI建议 -->
     <div class="cs-col">
       <div class="cs-col-head">对话信息</div>
       <div class="cs-col-body">
         <template v-if="activeConv">
           <div class="cs-side-section">
             <h4>男用户画像</h4>
             <div class="cs-profile">
               <div class="av" :class="'av-'+(store.user.av||1)">{{store.user.name?.[0]||'?'}}</div>
               <div class="iv">
                 <div class="n">{{store.user.name}} <span v-if="meInfo.vip" class="tag gold">VIP</span></div>
                 <div class="m">ID: {{store.user.id}} · {{store.user.city}}</div>
               </div>
             </div>
             <div class="profile-stats">
               <div class="ps"><div class="l">钻石</div><div class="v">💎 {{meInfo.diamonds}}</div></div>
               <div class="ps"><div class="l">余额</div><div class="v">¥{{meInfo.cash.toFixed(2)}}</div></div>
               <div class="ps"><div class="l">VIP</div><div class="v">{{meInfo.vip?'已开通':'未开通'}}</div></div>
               <div class="ps"><div class="l">实名</div><div class="v">{{meInfo.authed?'已认证':'未认证'}}</div></div>
             </div>
           </div>

           <div class="cs-side-section">
             <h4>💡 AI 建议回复</h4>
             <div class="ai-suggest">
               <div class="hd">🤖 GLM-4-Flash</div>
               <div class="tx" v-if="ui.aiLoading">思考中...</div>
               <div class="tx" v-else-if="ui.aiSuggest">{{ui.aiSuggest}}</div>
               <div class="tx" v-else style="color:#bbb;">点击下方按钮获取建议</div>
               <div class="act">
                 <button class="btn tiny ghost" @click="ops.askAI" :disabled="ui.aiLoading">{{ui.aiSuggest?'重新生成':'生成建议'}}</button>
