         <div><label>该时段最多推送</label><input class="input" type="number" min="1" v-model.number="s.maxPer" /></div>
-        <button class="btn tiny ghost" style="color:#ff3b5c;" @click="delSlot(i)">删除</button>
+        <button class="btn tiny ghost" style="color:#ff5c8a;" @click="delSlot(i)">删除</button>
