   .phone-shell::before{display:none;}
 }

 /* 屏幕容器 */
-.screen{width:100%;height:100%;background:linear-gradient(180deg,#fef6f9 0%,#f3eaff 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}
+.screen{width:100%;height:100%;background:linear-gradient(180deg,#1f0d3a 0%,#0a0418 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}

 /* 状态栏 */
-.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:13px;font-weight:600;color:#2d2d3a;flex-shrink:0;position:relative;z-index:10;}
+.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:13px;font-weight:600;color:#fff;flex-shrink:0;position:relative;z-index:10;}
 .status-bar .icons{display:flex;gap:5px;align-items:center;}
 .status-bar.dark{color:#fff;}

 /* 顶部导航条 */
-.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:#fff;flex-shrink:0;position:relative;z-index:9;}
-.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:22px;color:#2d2d3a;}
-.nav-bar .title{font-size:17px;font-weight:700;color:#2d2d3a;flex:1;text-align:center;}
-.nav-bar .right{min-width:32px;font-size:14px;color:#666;text-align:right;}
+.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:#1f0d3a;flex-shrink:0;position:relative;z-index:9;}
+.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:22px;color:#fff;}
+.nav-bar .title{font-size:17px;font-weight:700;color:#fff;flex:1;text-align:center;}
+.nav-bar .right{min-width:32px;font-size:14px;color:rgba(255,255,255,0.7);text-align:right;}
 .nav-bar.transparent{background:transparent;}
 .nav-bar.dark{background:transparent;}
 .nav-bar.dark .back,.nav-bar.dark .title,.nav-bar.dark .right{color:#fff;}

 /* 页面顶部大标题区 */
-.page-top{padding:6px 18px 14px;background:#fff;flex-shrink:0;}
-.page-top h1{font-size:24px;font-weight:800;color:#2d2d3a;margin-bottom:2px;}
-.page-top .sub{font-size:12px;color:#999;}
+.page-top{padding:6px 18px 14px;background:#1f0d3a;flex-shrink:0;}
+.page-top h1{font-size:24px;font-weight:800;color:#fff;margin-bottom:2px;}
+.page-top .sub{font-size:12px;color:rgba(255,255,255,0.55);}

 /* 主内容区 */
 .content{flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch;}
 .content::-webkit-scrollbar{display:none;}

 /* 底部 Tab Bar */
-.tab-bar{height:60px;display:flex;background:#fff;border-top:1px solid #f0f0f5;flex-shrink:0;padding-bottom:env(safe-area-inset-bottom,0);}
-.tab-bar .tab-item{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;color:#999;font-size:11px;gap:2px;}
+.tab-bar{height:60px;display:flex;background:#1f0d3a;border-top:1px solid rgba(255,255,255,0.06);flex-shrink:0;padding-bottom:env(safe-area-inset-bottom,0);}
+.tab-bar .tab-item{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;color:rgba(255,255,255,0.55);font-size:11px;gap:2px;}
 .tab-bar .tab-item .ico{font-size:22px;line-height:1;}
-.tab-bar .tab-item.active{color:#ff5a8a;font-weight:600;}
+.tab-bar .tab-item.active{color:#a18cff;font-weight:600;}

 /* 主CTA按钮 */
-.btn{display:inline-flex;align-items:center;justify-content:center;height:46px;padding:0 24px;border-radius:23px;font-size:15px;font-weight:600;background:linear-gradient(135deg,#ff5a8a 0%,#b66dff 100%);color:#fff;box-shadow:0 6px 18px rgba(255,90,138,.35);transition:transform .15s ease;}
+.btn{display:inline-flex;align-items:center;justify-content:center;height:46px;padding:0 24px;border-radius:23px;font-size:15px;font-weight:600;background:linear-gradient(135deg,#a18cff 0%,#ff8ad4 100%);color:#fff;box-shadow:0 6px 18px rgba(161,140,255,.35);transition:transform .15s ease;}
 .btn:active{transform:scale(.96);}
 .btn.block{width:100%;}
-.btn.gold{background:linear-gradient(135deg,#ffd75e 0%,#ff9a3c 100%);color:#5a3a00;box-shadow:0 6px 18px rgba(255,154,60,.35);}
-.btn.ghost{background:#fff;color:#ff5a8a;border:1.5px solid #ff5a8a;box-shadow:none;}
+.btn.gold{background:linear-gradient(135deg,#ffd966 0%,#ff9a3c 100%);color:#3a2a00;box-shadow:0 6px 18px rgba(255,154,60,.35);}
+.btn.ghost{background:rgba(161,140,255,0.1);color:#a18cff;border:1.5px solid #a18cff;box-shadow:none;}
 .btn.dark{background:#2d2d3a;box-shadow:0 6px 18px rgba(0,0,0,.2);}
 .btn.small{height:32px;padding:0 14px;border-radius:16px;font-size:13px;}
-.btn.danger{background:linear-gradient(135deg,#ff3b5c 0%,#ff5a8a 100%);}
+.btn.danger{background:linear-gradient(135deg,#ff5c8a 0%,#a18cff 100%);}
 .btn:disabled{opacity:.5;box-shadow:none;}

 /* 头像渐变 */
 .av{width:50px;height:50px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:18px;}
-.av-1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
-.av-2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
-.av-3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
-.av-4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
-.av-5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
-.av-6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
-.av-7{background:linear-gradient(135deg,#ff9a3c,#ff3b5c);}
-.av-8{background:linear-gradient(135deg,#7c5aff,#ff5a8a);}
+.av-1{background:linear-gradient(135deg,#a18cff,#ff8ad4);}
+.av-2{background:linear-gradient(135deg,#7ab5ff,#5eead4);}
+.av-3{background:linear-gradient(135deg,#ffd966,#ff9a3c);}
+.av-4{background:linear-gradient(135deg,#ff5c8a,#ffd966);}
+.av-5{background:linear-gradient(135deg,#5eead4,#7ab5ff);}
+.av-6{background:linear-gradient(135deg,#ff8ad4,#a18cff);}
+.av-7{background:linear-gradient(135deg,#ff9a3c,#ff5c8a);}
+.av-8{background:linear-gradient(135deg,#7ab5ff,#a18cff);}

 /* 通用卡片 */
-.card{background:#fff;border-radius:14px;padding:14px;box-shadow:0 6px 16px rgba(0,0,0,.05);}
+.card{background:#1f0d3a;border:1px solid rgba(180,140,255,.18);border-radius:14px;padding:14px;box-shadow:0 6px 20px rgba(10,4,24,.4);}

 /* 标签 */
-.tag{display:inline-flex;align-items:center;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:500;background:#fef0f5;color:#ff5a8a;}
-.tag.purple{background:#f3eaff;color:#7c5aff;}
-.tag.gold{background:#fff5d6;color:#ff9a3c;}
-.tag.green{background:#e8fbef;color:#22c55e;}
-.tag.gray{background:#f0f0f5;color:#666;}
-.tag.vip{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;font-weight:700;}
+.tag{display:inline-flex;align-items:center;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:500;background:rgba(180,140,255,0.15);color:#a18cff;}
+.tag.purple{background:#0a0418;color:#7ab5ff;}
+.tag.gold{background:rgba(255,217,102,0.15);color:#ff9a3c;}
+.tag.green{background:rgba(94,234,212,0.15);color:#5eead4;}
+.tag.gray{background:rgba(255,255,255,0.06);color:rgba(255,255,255,0.7);}
+.tag.vip{background:linear-gradient(135deg,#ffd966,#ff9a3c);color:#3a2a00;font-weight:700;}

 /* 红点 */
-.badge{display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 5px;background:#ff3b5c;color:#fff;font-size:10px;font-weight:700;border-radius:9px;}
+.badge{display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 5px;background:#ff5c8a;color:#fff;font-size:10px;font-weight:700;border-radius:9px;}
 .badge.dot{min-width:8px;height:8px;padding:0;border-radius:50%;}

 /* === ① 登录页 === */
-.login-page{padding:32px 28px;display:flex;flex-direction:column;height:100%;background:linear-gradient(180deg,#fef6f9 0%,#f3eaff 100%);}
+.login-page{padding:32px 28px;display:flex;flex-direction:column;height:100%;background:linear-gradient(180deg,#1f0d3a 0%,#0a0418 100%);}
 .login-page .logo{font-size:48px;text-align:center;margin-top:60px;}
-.login-page h1{font-size:32px;font-weight:800;text-align:center;margin-top:14px;background:linear-gradient(135deg,#ff5a8a,#b66dff);-webkit-background-clip:text;background-clip:text;color:transparent;}
-.login-page .slogan{font-size:14px;color:#999;text-align:center;margin-top:8px;}
+.login-page h1{font-size:32px;font-weight:800;text-align:center;margin-top:14px;background:linear-gradient(135deg,#a18cff,#ff8ad4);-webkit-background-clip:text;background-clip:text;color:transparent;}
+.login-page .slogan{font-size:14px;color:rgba(255,255,255,0.55);text-align:center;margin-top:8px;}
 .login-page .form{margin-top:48px;}
-.login-page .input-row{background:#fff;border-radius:12px;padding:14px 16px;margin-bottom:12px;display:flex;align-items:center;gap:10px;}
-.login-page .input-row .prefix{color:#ff5a8a;font-weight:600;}
-.login-page .input-row input{flex:1;font-size:15px;color:#2d2d3a;}
-.login-page .input-row .send-code{color:#ff5a8a;font-weight:600;font-size:13px;}
-.login-page .send-code.disabled{color:#bbb;}
-.login-page .agree{display:flex;align-items:flex-start;gap:6px;font-size:11px;color:#999;margin-top:14px;}
+.login-page .input-row{background:rgba(180,140,255,0.1);border:1px solid rgba(180,140,255,0.25);border-radius:12px;padding:14px 16px;margin-bottom:12px;display:flex;align-items:center;gap:10px;backdrop-filter:blur(8px);}
+.login-page .input-row .prefix{color:#a18cff;font-weight:600;}
+.login-page .input-row input{flex:1;font-size:15px;color:#fff;}
+.login-page .input-row input::placeholder{color:rgba(255,255,255,0.4);}
+.login-page .input-row .send-code{color:#ff8ad4;font-weight:600;font-size:13px;}
+.login-page .send-code.disabled{color:rgba(255,255,255,0.3);}
+.login-page .agree{display:flex;align-items:flex-start;gap:6px;font-size:11px;color:rgba(255,255,255,0.55);margin-top:14px;}
 .login-page .agree .cb{width:14px;height:14px;border-radius:50%;border:1.5px solid #ccc;flex-shrink:0;margin-top:2px;}
-.login-page .agree .cb.on{background:#ff5a8a;border-color:#ff5a8a;color:#fff;display:flex;align-items:center;justify-content:center;font-size:10px;}
-.login-page .agree a{color:#ff5a8a;}
+.login-page .agree .cb.on{background:#a18cff;border-color:#a18cff;color:#fff;display:flex;align-items:center;justify-content:center;font-size:10px;}
+.login-page .agree a{color:#a18cff;}
 .login-page .third{margin-top:40px;text-align:center;}
-.login-page .third .label{font-size:11px;color:#bbb;position:relative;margin-bottom:20px;}
+.login-page .third .label{font-size:11px;color:rgba(255,255,255,0.4);position:relative;margin-bottom:20px;}
 .login-page .third .label::before,.login-page .third .label::after{content:"";position:absolute;top:50%;width:40px;height:1px;background:#eee;}
 .login-page .third .label::before{right:calc(50% + 50px);}
 .login-page .third .label::after{left:calc(50% + 50px);}
 .login-page .third .ico-row{display:flex;justify-content:center;gap:24px;}
-.login-page .third .ico{width:44px;height:44px;border-radius:50%;background:#fff;display:flex;align-items:center;justify-content:center;font-size:22px;box-shadow:0 4px 10px rgba(0,0,0,.05);}
+.login-page .third .ico{width:44px;height:44px;border-radius:50%;background:#1f0d3a;display:flex;align-items:center;justify-content:center;font-size:22px;box-shadow:0 4px 14px rgba(10,4,24,.3);}

 /* === ② 发现/用户列表 === */
-.discover-tabs{display:flex;gap:18px;padding:0 18px 12px;background:#fff;overflow-x:auto;}
+.discover-tabs{display:flex;gap:18px;padding:0 18px 12px;background:#1f0d3a;overflow-x:auto;}
 .discover-tabs::-webkit-scrollbar{display:none;}
-.discover-tabs .tab{font-size:15px;color:#999;font-weight:500;white-space:nowrap;padding:6px 2px;position:relative;}
-.discover-tabs .tab.active{color:#2d2d3a;font-weight:700;font-size:17px;}
-.discover-tabs .tab.active::after{content:"";position:absolute;bottom:-2px;left:50%;transform:translateX(-50%);width:18px;height:3px;border-radius:2px;background:linear-gradient(90deg,#ff5a8a,#b66dff);}
-.filter-bar{display:flex;gap:8px;padding:10px 18px;background:#fff;overflow-x:auto;}
+.discover-tabs .tab{font-size:15px;color:rgba(255,255,255,0.55);font-weight:500;white-space:nowrap;padding:6px 2px;position:relative;}
+.discover-tabs .tab.active{color:#fff;font-weight:700;font-size:17px;}
+.discover-tabs .tab.active::after{content:"";position:absolute;bottom:-2px;left:50%;transform:translateX(-50%);width:18px;height:3px;border-radius:2px;background:linear-gradient(90deg,#a18cff,#ff8ad4);}
+.filter-bar{display:flex;gap:8px;padding:10px 18px;background:#1f0d3a;overflow-x:auto;}
 .filter-bar::-webkit-scrollbar{display:none;}
-.filter-bar .chip{padding:6px 12px;background:#f7f7fa;color:#666;font-size:12px;border-radius:14px;white-space:nowrap;}
-.filter-bar .chip.active{background:#fef0f5;color:#ff5a8a;font-weight:600;}
+.filter-bar .chip{padding:6px 12px;background:rgba(180,140,255,0.08);color:rgba(255,255,255,0.7);font-size:12px;border-radius:14px;white-space:nowrap;}
+.filter-bar .chip.active{background:rgba(180,140,255,0.15);color:#a18cff;font-weight:600;}
 .user-grid{padding:12px;display:grid;grid-template-columns:1fr 1fr;gap:12px;}
-.user-card{background:#fff;border-radius:14px;overflow:hidden;box-shadow:0 6px 16px rgba(0,0,0,.05);position:relative;}
+.user-card{background:#1f0d3a;border:1px solid rgba(180,140,255,.18);border-radius:14px;overflow:hidden;box-shadow:0 6px 20px rgba(10,4,24,.4);position:relative;}
 .user-card .cover{width:100%;aspect-ratio:1/1.15;display:flex;align-items:flex-end;padding:8px;position:relative;color:#fff;}
 .user-card .cover::before{content:"";position:absolute;inset:0;z-index:0;}
-.user-card.av-1 .cover::before{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
-.user-card.av-2 .cover::before{background:linear-gradient(135deg,#7c5aff,#4ade80);}
-.user-card.av-3 .cover::before{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
-.user-card.av-4 .cover::before{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
-.user-card.av-5 .cover::before{background:linear-gradient(135deg,#4ade80,#7c5aff);}
-.user-card.av-6 .cover::before{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
+.user-card.av-1 .cover::before{background:linear-gradient(135deg,#a18cff,#ff8ad4);}
+.user-card.av-2 .cover::before{background:linear-gradient(135deg,#7ab5ff,#5eead4);}
+.user-card.av-3 .cover::before{background:linear-gradient(135deg,#ffd966,#ff9a3c);}
+.user-card.av-4 .cover::before{background:linear-gradient(135deg,#ff5c8a,#ffd966);}
+.user-card.av-5 .cover::before{background:linear-gradient(135deg,#5eead4,#7ab5ff);}
+.user-card.av-6 .cover::before{background:linear-gradient(135deg,#ff8ad4,#a18cff);}
 .user-card .cover-inner{position:relative;z-index:1;width:100%;}
 .user-card .top-flags{position:absolute;top:8px;left:8px;display:flex;gap:4px;z-index:2;}
 .user-card .flag{padding:2px 6px;font-size:10px;background:rgba(0,0,0,.4);color:#fff;border-radius:8px;backdrop-filter:blur(4px);}
-.user-card .flag.online{background:#4ade80;}
-.user-card .flag.vip{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;font-weight:700;}
+.user-card .flag.online{background:#5eead4;}
+.user-card .flag.vip{background:linear-gradient(135deg,#ffd966,#ff9a3c);color:#3a2a00;font-weight:700;}
 .user-card .info{padding:8px 10px;}
-.user-card .info .name{font-size:14px;font-weight:700;color:#2d2d3a;display:flex;align-items:center;gap:4px;}
-.user-card .info .meta{font-size:11px;color:#999;margin-top:2px;}
+.user-card .info .name{font-size:14px;font-weight:700;color:#fff;display:flex;align-items:center;gap:4px;}
+.user-card .info .meta{font-size:11px;color:rgba(255,255,255,0.55);margin-top:2px;}
 .user-card .info .tags{display:flex;gap:4px;margin-top:6px;flex-wrap:wrap;}

 /* === ③ 消息列表 === */
-.msg-quick{padding:14px 18px;background:#fff;display:grid;grid-template-columns:repeat(4,1fr);gap:8px;}
+.msg-quick{padding:14px 18px;background:#1f0d3a;display:grid;grid-template-columns:repeat(4,1fr);gap:8px;}
 .msg-quick .qi{display:flex;flex-direction:column;align-items:center;gap:6px;position:relative;}
 .msg-quick .qi .ico{width:44px;height:44px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;color:#fff;}
-.msg-quick .qi .ico.c1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
-.msg-quick .qi .ico.c2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
-.msg-quick .qi .ico.c3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
-.msg-quick .qi .ico.c4{background:linear-gradient(135deg,#4ade80,#22c55e);}
-.msg-quick .qi .lbl{font-size:11px;color:#666;}
+.msg-quick .qi .ico.c1{background:linear-gradient(135deg,#a18cff,#ff8ad4);}
+.msg-quick .qi .ico.c2{background:linear-gradient(135deg,#7ab5ff,#5eead4);}
+.msg-quick .qi .ico.c3{background:linear-gradient(135deg,#ffd966,#ff9a3c);}
+.msg-quick .qi .ico.c4{background:linear-gradient(135deg,#5eead4,#5eead4);}
+.msg-quick .qi .lbl{font-size:11px;color:rgba(255,255,255,0.7);}
 .msg-quick .qi .bd{position:absolute;top:-4px;right:14px;}
-.chat-list{background:#fff;}
-.chat-item{display:flex;align-items:center;padding:12px 18px;gap:12px;border-bottom:1px solid #f5f5f8;}
-.chat-item:active{background:#fafafd;}
+.chat-list{background:transparent;}
+.chat-item{display:flex;align-items:center;padding:12px 18px;gap:12px;border-bottom:1px solid rgba(255,255,255,0.06);}
+.chat-item:active{background:rgba(180,140,255,0.06);}
 .chat-item .av-wrap{position:relative;}
-.chat-item .av-wrap .online-dot{position:absolute;bottom:0;right:0;width:10px;height:10px;background:#4ade80;border:2px solid #fff;border-radius:50%;}
+.chat-item .av-wrap .online-dot{position:absolute;bottom:0;right:0;width:10px;height:10px;background:#5eead4;border:2px solid #fff;border-radius:50%;}
 .chat-item .info{flex:1;min-width:0;}
 .chat-item .info .row1{display:flex;justify-content:space-between;align-items:center;}
-.chat-item .info .name{font-size:15px;font-weight:600;color:#2d2d3a;display:flex;align-items:center;gap:4px;}
-.chat-item .info .time{font-size:11px;color:#bbb;}
-.chat-item .info .last{font-size:13px;color:#999;margin-top:4px;display:flex;justify-content:space-between;align-items:center;}
+.chat-item .info .name{font-size:15px;font-weight:600;color:#fff;display:flex;align-items:center;gap:4px;}
+.chat-item .info .time{font-size:11px;color:rgba(255,255,255,0.4);}
+.chat-item .info .last{font-size:13px;color:rgba(255,255,255,0.55);margin-top:4px;display:flex;justify-content:space-between;align-items:center;}
 .chat-item .info .last span{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:200px;}

 /* === ④ 个人中心 === */
-.me-header{padding:18px;background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;position:relative;}
+.me-header{padding:18px;background:linear-gradient(135deg,#a18cff,#ff8ad4);color:#fff;position:relative;}
 .me-header .top-row{display:flex;align-items:center;gap:14px;}
 .me-header .av{width:64px;height:64px;font-size:24px;border:3px solid rgba(255,255,255,.3);}
 .me-header .ns{flex:1;}
 .me-header .name{font-size:20px;font-weight:800;display:flex;align-items:center;gap:6px;}
 .me-header .id{font-size:11px;opacity:.8;margin-top:2px;}
 .me-header .sign{font-size:12px;margin-top:6px;opacity:.9;}
 .me-header .edit{position:absolute;top:18px;right:18px;padding:5px 12px;background:rgba(255,255,255,.2);border-radius:14px;font-size:11px;color:#fff;}
 .me-stats{display:grid;grid-template-columns:repeat(4,1fr);margin-top:18px;text-align:center;}
 .me-stats .num{font-size:18px;font-weight:800;}
 .me-stats .lbl{font-size:11px;opacity:.85;margin-top:2px;}
