 // 否则会一律回退到 MOCK_USERS[0]（小诗），导致所有会话都显示成"小诗"。
 const findUser = id => {
   if(id == null) return MOCK_USERS[0]
   // eq 比较，兼容字符串/数字
   const eq = (a,b)=> a === b || String(a) === String(b)
   let u = MOCK_USERS.find(u=>eq(u.id, id))
   if(u) return u
