         av: f.av || f.avatarNo || 1,
         age: f.age || 22,
         city: f.city || '',
         dist: f.dist || '',
         tags: Array.isArray(f.tags) ? f.tags : [],
         sign: f.sign || '',
         online: !!f.online,
         vip: !!f.vip,
         height: f.height || 165,
         weight: f.weight || 50,
         job: f.job || '',
         edu: f.edu || '',
         home: f.home || f.hometown || '',
         love: f.love || f.loveStatus || '单身'
       }
       MOCK_USERS.push(conv)
       return conv
     }
   }
   return MOCK_USERS[0]
 }

