 /* ===================== 业务方法 =====================
  * 所有方法均同步返回 boolean（与旧 UI 兼容），
  * 内部触发的 API 调用是异步的：成功后通过 toast/Store 反向更新 UI。
  * 调用失败 / 后端不可达 时降级到原本地 Mock 逻辑。
  */
 const biz = {
   // ---------- 充值 ----------
   recharge(rmb, diamond){
     // 本地立即扣加，保证体验
     store.diamonds += diamond
     store.transactions.unshift({id:'t'+Date.now(), type:'out', cat:'recharge', t1:`充值 ${diamond}💎`, t2:'刚刚', amt:rmb})
     toast(`充值成功 +${diamond}💎`)
     if(!store.firstRechargeShown){ store.firstRechargeShown = true }

     // 异步同步到后端：根据金额匹配套餐ID（60/300/680/1280/3280/6480 -> 1/2/3/4/5/6）
     if(apiOn()){
       const packageMap = {60:1, 300:2, 680:3, 1280:4, 3280:5, 6480:6}
       const pkgId = packageMap[rmb]
       if(pkgId){
         API.payment.recharge(pkgId, 'wechat').catch(err=>{
           console.warn('[api] recharge failed, kept local:', err.message)
         })
       }
     }
   },

   // ---------- 聊天消息 ----------
   sendChatMsg(chatId, text){
     const chat = store.chats.find(c=>c.id===chatId)
     if(!chat) return false
     let cost = 1
     if(store.user.vip && store.chatFreeRemain>0){
       store.chatFreeRemain--
       cost = 0
     }else if(store.diamonds < 1){
-      toast('钻石不足，请充值')
+      toast('你的星屑不够照亮这条消息')
       go('/recharge')
       return false
     }else{
       store.diamonds -= 1
     }
     chat.msgs.push({type:'out', text, time:'刚刚', cost})
     chat.lastMsg = text
     chat.time = '刚刚'

     // 异步同步到后端（仅当 chat.sessionId 已绑定后端会话时）
     if(apiOn() && chat.sessionId){
       API.chat.sendMessage(chat.sessionId, text).catch(err=>{
         console.warn('[api] sendMessage failed, kept local:', err.message)
       })
     }

     // 本地模拟回复（无后端时维持原体验）
     if(!apiOn() || !chat.sessionId){
       setTimeout(()=>{
         const replies = ['嗯嗯～','你说的对','哈哈～','是这样吗？','听你的','想见你了']
         const r = replies[Math.floor(Math.random()*replies.length)]
         chat.msgs.push({type:'in', text:r, time:'刚刚'})
         chat.lastMsg = r
       }, 1200)
     }
     return true
   },

   // ---------- 赠送礼物 ----------
   sendGift(chatId, gift, num){
     const total = gift.price * num
     if(store.diamonds < total){
-      toast('钻石不足，请充值')
+      toast('你的星屑不够照亮这条消息')
       return false
     }
     store.diamonds -= total
     const chat = store.chats.find(c=>c.id===chatId)
     if(chat){
       chat.msgs.push({type:'gift', text:gift.name+(num>1?` ×${num}`:''), em:gift.em, price:total, from:'me'})
       chat.lastMsg = `[礼物] ${gift.name} ×${num}`
       chat.time = '刚刚'
     }
     toast(`已送出 ${gift.name} ×${num}`)

     // 异步同步：将本地 gift.id 映射为后端 giftId（1-12按顺序对应）
     if(apiOn() && chat && chat.peerUserId && gift.backendId){
       API.gift.send(chat.peerUserId, gift.backendId, num, chat.sessionId).catch(err=>{
         console.warn('[api] sendGift failed, kept local:', err.message)
       })
     }
     return true
   },

   // ---------- 提现 ----------
   withdraw(amt){
     if(amt < 10){ toast('单笔最低 ¥10'); return false }
     if(amt > store.cash){ toast('余额不足'); return false }
     if(!store.isAuthed){ toast('请先完成实名认证'); go('/auth'); return false }
     const fee = Math.max(1, amt * 0.006).toFixed(2)
     store.cash = +(store.cash - amt).toFixed(2)
     store.transactions.unshift({id:'t'+Date.now(), type:'out', cat:'withdraw', t1:`提现 ¥${amt}（手续费 ¥${fee}）`, t2:'刚刚', amt})
     toast(`提现成功 ¥${(amt-fee).toFixed(2)} 已到账`)

     if(apiOn()){
       API.payment.withdraw(amt, 'wechat', '').catch(err=>{
         console.warn('[api] withdraw failed, kept local:', err.message)
       })
     }
     return true
   },

   // ---------- VIP 开通 ----------
   openVip(plan){
     const days = {month:30, season:90, year:365}
     store.user.vip = true
     store.user.vipExpire = `${days[plan]}天后`
     toast(`已开通 ${plan==='month'?'月':plan==='season'?'季':'年'}卡 VIP！`)

     if(apiOn()){
       const planTypeMap = {month:'month', season:'quarter', year:'year'}
       API.vip.subscribe(planTypeMap[plan]||'month', 'wechat').catch(err=>{
         console.warn('[api] openVip failed, kept local:', err.message)
       })
     }
     return true
   },

   // ---------- 视频通话扣费 ----------
   callMinute(uid){
     let rate = 6
     if(store.user.vip) rate = Math.ceil(rate*0.8)
     if(store.diamonds < rate) return false
     store.diamonds -= rate
     // 视频通话扣费暂未提供独立后端接口，仅本地扣
     return rate
   },

   // ---------- 实名认证 ----------
   finishAuth(){
     store.isAuthed = true
     store.diamonds += 100
     toast('实名认证成功 +100💎')
     // 后端实名认证接口待补充（TODO）
   },

   // ---------- 新人资料 ----------
   finishOnboard(data){
     Object.assign(store.user, data)
     store.onboarded = true
     store.diamonds += 88
     toast('资料完善 +88💎')

     if(apiOn()){
       API.user.updateProfile({
         nickname: data.name,
         avatarNo: data.av,
         gender: data.gender === '男' ? 'M' : 'F',
         age: data.age,
         city: data.city,
         height: data.height,
         job: data.job,
         sign: data.sign,
         tags: data.tags ? JSON.stringify(data.tags) : null
       }).catch(err=>{
         console.warn('[api] updateProfile failed:', err.message)
       })
     }
   },

   // ---------- 登录 ----------
   login(){
     store.loggedIn = true
     toast('登录成功')
   },

   // ---------- 真实后端登录（手机+验证码） ----------
   loginByApi(phone, code){
     if(!apiOn()) return Promise.reject(new Error('后端未启用'))
     return API.auth.login(phone, code).then(data=>{
       store.loggedIn = true
       if(data){
         if(data.nickname) store.user.name = data.nickname
         if(data.diamonds !== undefined) store.diamonds = data.diamonds
         if(data.isVip) store.user.vip = true
         if(data.onboarded) store.onboarded = true
       }
       toast('登录成功')
       // 登录后建立 WebSocket
       try { API.ws.connect() } catch(e) {}
       return data
     })
   },

   // ---------- 发送验证码 ----------
   sendCode(phone){
     if(!apiOn()) { toast('验证码已发送（演示）'); return Promise.resolve() }
     return API.auth.sendCode(phone).then(()=>{
       toast('验证码已发送（演示验证码：123456）')
     }).catch(err=>{
       toast('发送失败：'+err.message+'，演示验证码：123456')
     })
   },

   // ---------- 退出登录 ----------
   logout(){
     if(apiOn()) { try { API.auth.logout() } catch(e){} try { API.ws.disconnect() } catch(e){} }
     Object.assign(store, JSON.parse(JSON.stringify(DEFAULT_STORE)))
     toast('已退出登录')
   }
 }

 // ===== WebSocket 推送：收到新消息时插入到对应会话 =====
 if(apiOn()){
   API.ws.on(function(msg){
     if(!msg) return
     if(msg.type === 'new_message' && msg.sessionId){
       const chat = store.chats.find(c=>c.sessionId === msg.sessionId)
       if(chat){
         chat.msgs.push({type:'in', text:msg.content || '', time:'刚刚'})
         chat.lastMsg = msg.content || ''
         chat.time = '刚刚'
         chat.unread = (chat.unread||0) + 1
       }
     }else if(msg.type === 'new_gift'){
       toast(`收到 ${msg.giftIcon||'🎁'} ${msg.giftName||'礼物'} ×${msg.quantity||1}`)
     }
   })
   // 若已登录则立即连接
   if(API.auth.isLoggedIn()) { try { API.ws.connect() } catch(e){} }
 }

