 const PageChat = {
   components:{StatusBar,NavBar},
   setup(){
     const route = computed(()=>parseRoute(currentRoute.value))
     const chat = computed(()=>store.chats.find(c=>c.id===route.value.param) || store.chats[0] || {id:'',uid:'',msgs:[],lastMsg:'',time:''})
     const user = computed(()=>findUser(chat.value && chat.value.uid))
     const txt = ref('')
     const aiLoading = ref(false)
     const aiSuggest = ref('')
     const tools = [
       {ic:'🎁',lbl:'礼物',act:()=>uiState.giftPanel=true},
       {ic:'📷',lbl:'照片',act:()=>toast('调起相机')},
       {ic:'📞',lbl:'视频',act:()=>go('/call/'+chat.value.uid)},
       {ic:'📍',lbl:'位置',act:()=>toast('发送位置')},
       {ic:'🧧',lbl:'红包',act:()=>toast('打开红包')},
     ]
     const send = ()=>{
       if(!txt.value.trim()) return
       const ok = biz.sendChatMsg(chat.value.id, txt.value)
       if(ok){ txt.value=''; aiSuggest.value='' }
     }
     const goToRecharge = ()=>go('/recharge')
     const askAI = async ()=>{
       if(aiLoading.value) return
       if(!store.csConfig.aiKey){ toast('未配置 AI Key（请在后台设置）'); return }
       aiLoading.value = true
       aiSuggest.value = ''
       try{
         const last5 = chat.value.msgs.slice(-6).filter(m=>m.type==='in'||m.type==='out')
         const dialog = last5.map(m=>({
           role: m.type==='in'?'user':'assistant',
           content: m.text
         }))
         const sys = `你是一位男性的恋爱沟通教练。对方（${user.value.name}, ${user.value.age}岁, ${user.value.city}, ${user.value.sign}）最近发来消息。请用第一人称（我）给出一个自然、有趣、不油腻、30字以内的回复，让对话更轻松推进。只输出回复本身，不要解释。`
         const txt2 = await glm.chat([
           {role:'system', content:sys},
           ...dialog
         ])
         aiSuggest.value = txt2
       }catch(e){ toast('AI出错: '+e.message) }
       aiLoading.value = false
     }
     const useAI = ()=>{ txt.value = aiSuggest.value; aiSuggest.value='' }
     return {chat,user,txt,tools,send,store,goToRecharge,askAI,useAI,aiLoading,aiSuggest,back}
