     const fee = computed(()=>{
       const a = +amt.value || 0
       return Math.max(1, a*0.006).toFixed(2)
     })
     const arrive = computed(()=>{
       const a = +amt.value || 0
       return Math.max(0, a - +fee.value).toFixed(2)
     })
