 const ViewPush = {
   setup(){
     const addSlot = ()=>{
       store.pushRules.timeSlots.push({start:'08:00',end:'10:00',maxPer:1})
     }
     const delSlot = (i)=>{
       store.pushRules.timeSlots.splice(i,1)
     }
     const save = ()=>toast('已保存（自动持久化）')
     const testNow = ()=>{
       if(!store.fakeUsers.length){ toast('请先创建假用户'); return }
       if(!store.loggedIn){ toast('男用户端未登录'); return }
       const fu = store.fakeUsers[Math.floor(Math.random()*store.fakeUsers.length)]
       ops.manualPush(fu.id)
     }
     return {store, addSlot, delSlot, save, testNow}
   },
   template:`<div>
     <div class="card" style="margin-bottom:14px;">
       <div class="card-title">
         <span>自动推送总开关</span>
         <div style="display:flex;align-items:center;gap:10px;font-size:12px;">
           <span :style="{color:store.pushRules.enabled?'#22c55e':'#999'}">{{store.pushRules.enabled?'● 运行中':'○ 已暂停'}}</span>
           <div class="sw" :class="{on:store.pushRules.enabled}" @click="store.pushRules.enabled=!store.pushRules.enabled"></div>
         </div>
       </div>
       <div style="font-size:12px;color:#888;line-height:1.7;">
         开启后：app.html 端的 Worker 会按下方时段策略，从假用户池随机选人，向当前登录的男用户主动发起打招呼。<br>
         Worker 每 1-3 分钟检查一次时段，命中时段且未达上限即推送。
