 .card{background:#fff;border-radius:14px;padding:14px;box-shadow:0 6px 16px rgba(0,0,0,.05);}

 /* 标签 */
 .tag{display:inline-flex;align-items:center;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:500;background:#fef0f5;color:#ff5a8a;}
 .tag.purple{background:#f3eaff;color:#7c5aff;}
 .tag.gold{background:#fff5d6;color:#ff9a3c;}
 .tag.green{background:#e8fbef;color:#22c55e;}
 .tag.gray{background:#f0f0f5;color:#666;}
 .tag.vip{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;font-weight:700;}

 /* 红点 */
 .badge{display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 5px;background:#ff3b5c;color:#fff;font-size:10px;font-weight:700;border-radius:9px;}
 .badge.dot{min-width:8px;height:8px;padding:0;border-radius:50%;}

 /* === ① 登录页 === */
 .login-page{padding:32px 28px;display:flex;flex-direction:column;height:100%;background:linear-gradient(180deg,#fef6f9 0%,#f3eaff 100%);}
 .login-page .logo{font-size:48px;text-align:center;margin-top:60px;}
 .login-page h1{font-size:32px;font-weight:800;text-align:center;margin-top:14px;background:linear-gradient(135deg,#ff5a8a,#b66dff);-webkit-background-clip:text;background-clip:text;color:transparent;}
 .login-page .slogan{font-size:14px;color:#999;text-align:center;margin-top:8px;}
 .login-page .form{margin-top:48px;}
 .login-page .input-row{background:#fff;border-radius:12px;padding:14px 16px;margin-bottom:12px;display:flex;align-items:center;gap:10px;}
 .login-page .input-row .prefix{color:#ff5a8a;font-weight:600;}
 .login-page .input-row input{flex:1;font-size:15px;color:#2d2d3a;}
 .login-page .input-row .send-code{color:#ff5a8a;font-weight:600;font-size:13px;}
 .login-page .send-code.disabled{color:#bbb;}
 .login-page .agree{display:flex;align-items:flex-start;gap:6px;font-size:11px;color:#999;margin-top:14px;}
 .login-page .agree .cb{width:14px;height:14px;border-radius:50%;border:1.5px solid #ccc;flex-shrink:0;margin-top:2px;}
 .login-page .agree .cb.on{background:#ff5a8a;border-color:#ff5a8a;color:#fff;display:flex;align-items:center;justify-content:center;font-size:10px;}
 .login-page .agree a{color:#ff5a8a;}
 .login-page .third{margin-top:40px;text-align:center;}
 .login-page .third .label{font-size:11px;color:#bbb;position:relative;margin-bottom:20px;}
 .login-page .third .label::before,.login-page .third .label::after{content:"";position:absolute;top:50%;width:40px;height:1px;background:#eee;}
 .login-page .third .label::before{right:calc(50% + 50px);}
 .login-page .third .label::after{left:calc(50% + 50px);}
 .login-page .third .ico-row{display:flex;justify-content:center;gap:24px;}
 .login-page .third .ico{width:44px;height:44px;border-radius:50%;background:#fff;display:flex;align-items:center;justify-content:center;font-size:22px;box-shadow:0 4px 10px rgba(0,0,0,.05);}

 /* === ② 发现/用户列表 === */
 .discover-tabs{display:flex;gap:18px;padding:0 18px 12px;background:#fff;overflow-x:auto;}
 .discover-tabs::-webkit-scrollbar{display:none;}
 .discover-tabs .tab{font-size:15px;color:#999;font-weight:500;white-space:nowrap;padding:6px 2px;position:relative;}
 .discover-tabs .tab.active{color:#2d2d3a;font-weight:700;font-size:17px;}
 .discover-tabs .tab.active::after{content:"";position:absolute;bottom:-2px;left:50%;transform:translateX(-50%);width:18px;height:3px;border-radius:2px;background:linear-gradient(90deg,#ff5a8a,#b66dff);}
 .filter-bar{display:flex;gap:8px;padding:10px 18px;background:#fff;overflow-x:auto;}
 .filter-bar::-webkit-scrollbar{display:none;}
 .filter-bar .chip{padding:6px 12px;background:#f7f7fa;color:#666;font-size:12px;border-radius:14px;white-space:nowrap;}
 .filter-bar .chip.active{background:#fef0f5;color:#ff5a8a;font-weight:600;}
 .user-grid{padding:12px;display:grid;grid-template-columns:1fr 1fr;gap:12px;}
 .user-card{background:#fff;border-radius:14px;overflow:hidden;box-shadow:0 6px 16px rgba(0,0,0,.05);position:relative;}
 .user-card .cover{width:100%;aspect-ratio:1/1.15;display:flex;align-items:flex-end;padding:8px;position:relative;color:#fff;}
 .user-card .cover::before{content:"";position:absolute;inset:0;z-index:0;}
 .user-card.av-1 .cover::before{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
 .user-card.av-2 .cover::before{background:linear-gradient(135deg,#7c5aff,#4ade80);}
 .user-card.av-3 .cover::before{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
 .user-card.av-4 .cover::before{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
 .user-card.av-5 .cover::before{background:linear-gradient(135deg,#4ade80,#7c5aff);}
 .user-card.av-6 .cover::before{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
 .user-card .cover-inner{position:relative;z-index:1;width:100%;}
 .user-card .top-flags{position:absolute;top:8px;left:8px;display:flex;gap:4px;z-index:2;}
 .user-card .flag{padding:2px 6px;font-size:10px;background:rgba(0,0,0,.4);color:#fff;border-radius:8px;backdrop-filter:blur(4px);}
 .user-card .flag.online{background:#4ade80;}
 .user-card .flag.vip{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;font-weight:700;}
 .user-card .info{padding:8px 10px;}
 .user-card .info .name{font-size:14px;font-weight:700;color:#2d2d3a;display:flex;align-items:center;gap:4px;}
 .user-card .info .meta{font-size:11px;color:#999;margin-top:2px;}
 .user-card .info .tags{display:flex;gap:4px;margin-top:6px;flex-wrap:wrap;}

 /* === ③ 消息列表 === */
 .msg-quick{padding:14px 18px;background:#fff;display:grid;grid-template-columns:repeat(4,1fr);gap:8px;}
 .msg-quick .qi{display:flex;flex-direction:column;align-items:center;gap:6px;position:relative;}
 .msg-quick .qi .ico{width:44px;height:44px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;color:#fff;}
 .msg-quick .qi .ico.c1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
 .msg-quick .qi .ico.c2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
 .msg-quick .qi .ico.c3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
 .msg-quick .qi .ico.c4{background:linear-gradient(135deg,#4ade80,#22c55e);}
 .msg-quick .qi .lbl{font-size:11px;color:#666;}
 .msg-quick .qi .bd{position:absolute;top:-4px;right:14px;}
 .chat-list{background:#fff;}
 .chat-item{display:flex;align-items:center;padding:12px 18px;gap:12px;border-bottom:1px solid #f5f5f8;}
 .chat-item:active{background:#fafafd;}
 .chat-item .av-wrap{position:relative;}
 .chat-item .av-wrap .online-dot{position:absolute;bottom:0;right:0;width:10px;height:10px;background:#4ade80;border:2px solid #fff;border-radius:50%;}
 .chat-item .info{flex:1;min-width:0;}
 .chat-item .info .row1{display:flex;justify-content:space-between;align-items:center;}
 .chat-item .info .name{font-size:15px;font-weight:600;color:#2d2d3a;display:flex;align-items:center;gap:4px;}
 .chat-item .info .time{font-size:11px;color:#bbb;}
 .chat-item .info .last{font-size:13px;color:#999;margin-top:4px;display:flex;justify-content:space-between;align-items:center;}
 .chat-item .info .last span{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:200px;}

 /* === ④ 个人中心 === */
 .me-header{padding:18px;background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;position:relative;}
 .me-header .top-row{display:flex;align-items:center;gap:14px;}
 .me-header .av{width:64px;height:64px;font-size:24px;border:3px solid rgba(255,255,255,.3);}
 .me-header .ns{flex:1;}
 .me-header .name{font-size:20px;font-weight:800;display:flex;align-items:center;gap:6px;}
 .me-header .id{font-size:11px;opacity:.8;margin-top:2px;}
 .me-header .sign{font-size:12px;margin-top:6px;opacity:.9;}
 .me-header .edit{position:absolute;top:18px;right:18px;padding:5px 12px;background:rgba(255,255,255,.2);border-radius:14px;font-size:11px;color:#fff;}
 .me-stats{display:grid;grid-template-columns:repeat(4,1fr);margin-top:18px;text-align:center;}
 .me-stats .num{font-size:18px;font-weight:800;}
 .me-stats .lbl{font-size:11px;opacity:.85;margin-top:2px;}
 .vip-banner{margin:14px;padding:14px;border-radius:14px;background:linear-gradient(135deg,#3a2a52,#1a0d2e);color:#ffd75e;display:flex;align-items:center;gap:12px;position:relative;overflow:hidden;}
 .vip-banner::after{content:"👑";position:absolute;right:-10px;top:-10px;font-size:80px;opacity:.1;}
 .vip-banner .vip-i{font-size:28px;}
 .vip-banner .vt{flex:1;}
 .vip-banner .vt .t1{font-size:14px;font-weight:700;}
 .vip-banner .vt .t2{font-size:11px;opacity:.8;margin-top:2px;}
 .vip-banner .vb{padding:6px 14px;background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;border-radius:14px;font-size:12px;font-weight:700;}
 .menu-group{margin:0 14px 14px;background:#fff;border-radius:14px;overflow:hidden;}
 .menu-item{display:flex;align-items:center;padding:14px;gap:12px;border-bottom:1px solid #f5f5f8;}
 .menu-item:last-child{border-bottom:none;}
 .menu-item:active{background:#fafafd;}
 .menu-item .ico{width:32px;height:32px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:18px;color:#fff;}
 .menu-item .lbl{flex:1;font-size:14px;color:#2d2d3a;}
 .menu-item .rt{font-size:12px;color:#999;}
 .menu-item .arr{color:#ccc;font-size:18px;}

 /* === ⑤ 个人主页 === */
 .profile-page{background:#f5f5f8;height:100%;display:flex;flex-direction:column;overflow:hidden;}
 .profile-cover{height:380px;position:relative;color:#fff;flex-shrink:0;}
 .profile-cover.av-1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
 .profile-cover.av-2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
 .profile-cover.av-3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
 .profile-cover.av-4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
 .profile-cover.av-5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
 .profile-cover.av-6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
 .profile-cover::after{content:"";position:absolute;bottom:0;left:0;right:0;height:120px;background:linear-gradient(180deg,transparent,rgba(0,0,0,.5));}
 .profile-cover .top{position:absolute;top:48px;left:0;right:0;padding:0 14px;display:flex;justify-content:space-between;align-items:center;z-index:2;}
 .profile-cover .ic-btn{width:34px;height:34px;border-radius:50%;background:rgba(0,0,0,.3);display:flex;align-items:center;justify-content:center;color:#fff;font-size:18px;backdrop-filter:blur(8px);}
 .profile-cover .info{position:absolute;bottom:14px;left:18px;right:18px;z-index:2;}
 .profile-cover .name{font-size:24px;font-weight:800;display:flex;align-items:center;gap:6px;}
 .profile-cover .meta{font-size:12px;margin-top:4px;opacity:.9;display:flex;align-items:center;gap:10px;}
 .profile-cover .sign{font-size:13px;margin-top:8px;opacity:.95;}
 .profile-content{flex:1;overflow-y:auto;background:#f5f5f8;padding-bottom:80px;}
 .profile-content::-webkit-scrollbar{display:none;}
 .profile-section{background:#fff;margin:10px 14px;padding:14px;border-radius:14px;}
 .profile-section h3{font-size:15px;font-weight:700;margin-bottom:12px;}
 .info-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
 .info-grid .it{display:flex;flex-direction:column;gap:2px;}
 .info-grid .it .k{font-size:11px;color:#999;}
 .info-grid .it .v{font-size:13px;color:#2d2d3a;font-weight:500;}
 .interest-tags{display:flex;flex-wrap:wrap;gap:8px;}
 .album-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;}
 .album-grid .photo{aspect-ratio:1;border-radius:8px;}
 .album-grid .photo.p1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
 .album-grid .photo.p2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
 .album-grid .photo.p3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
 .album-grid .photo.p4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
 .album-grid .photo.p5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
 .album-grid .photo.p6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
 .profile-cta{position:absolute;bottom:0;left:0;right:0;padding:12px 14px;background:#fff;display:flex;gap:8px;box-shadow:0 -4px 16px rgba(0,0,0,.05);padding-bottom:calc(12px + env(safe-area-inset-bottom,0));}
 .profile-cta .b{flex:1;height:44px;border-radius:22px;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:600;gap:4px;}
 .profile-cta .b.b-gift{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;}
 .profile-cta .b.b-fav{background:#fef0f5;color:#ff5a8a;}
 .profile-cta .b.b-chat{background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;box-shadow:0 6px 18px rgba(255,90,138,.35);flex:2;}

 /* === 通用 Toast === */
 .toast{position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:rgba(0,0,0,.75);color:#fff;padding:10px 18px;border-radius:8px;font-size:13px;z-index:99999;animation:fadeIn .2s;}
 @keyframes fadeIn{from{opacity:0;}to{opacity:1;}}

 /* === 通用 Modal === */
 .modal-mask{position:absolute;inset:0;background:rgba(0,0,0,.5);z-index:1000;display:flex;align-items:center;justify-content:center;animation:fadeIn .2s;}
 .modal-mask.bottom{align-items:flex-end;}
 .modal-card{background:#fff;border-radius:18px;width:85%;max-width:320px;overflow:hidden;animation:modalIn .25s;}
 .modal-card.full{width:100%;border-radius:18px 18px 0 0;max-width:none;}
 @keyframes modalIn{from{transform:scale(.9);opacity:0;}to{transform:scale(1);opacity:1;}}

 /* 空状态 */
 .empty{padding:60px 20px;text-align:center;color:#bbb;font-size:13px;}
 .empty .ei{font-size:48px;opacity:.5;margin-bottom:14px;}

 /* === ⑥ 充值 === */
 .recharge-page{background:linear-gradient(180deg,#1a0d2e 0%,#2a1a3d 100%);color:#fff;height:100%;overflow-y:auto;}
 .recharge-page::-webkit-scrollbar{display:none;}
 .recharge-balance{padding:24px 18px;text-align:center;}
