 .recharge-balance .num{font-size:36px;font-weight:800;color:#ffd75e;margin-top:6px;display:flex;align-items:center;justify-content:center;gap:6px;}
 .recharge-balance .num .di{font-size:24px;}
 .first-bonus{margin:0 18px 14px;padding:10px 14px;background:linear-gradient(135deg,rgba(255,215,94,.2),rgba(255,154,60,.1));border:1px solid rgba(255,215,94,.4);border-radius:10px;color:#ffd75e;font-size:12px;font-weight:600;display:flex;align-items:center;gap:8px;}
 .pkg-grid{padding:0 14px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;}
 .pkg-card{background:rgba(255,255,255,.08);border:1.5px solid transparent;border-radius:12px;padding:14px 8px;text-align:center;position:relative;transition:all .2s;}
