 .pkg-card.hot::before{content:"超值热销";position:absolute;top:-8px;left:50%;transform:translateX(-50%);background:linear-gradient(135deg,#ff3b5c,#ff5a8a);color:#fff;font-size:10px;font-weight:700;padding:2px 8px;border-radius:8px;}
 .pkg-card .di{font-size:24px;font-weight:800;color:#ffd75e;display:flex;align-items:center;justify-content:center;gap:2px;}
 .pkg-card .di .ic{font-size:16px;}
 .pkg-card .ex{font-size:10px;color:#4ade80;margin-top:2px;}
 .pkg-card .price{font-size:13px;font-weight:600;margin-top:6px;color:#fff;}
 .pay-section{margin:18px 14px;background:rgba(255,255,255,.08);border-radius:12px;padding:14px;}
 .pay-section h4{font-size:14px;font-weight:700;margin-bottom:12px;}
 .pay-method{display:flex;align-items:center;padding:10px 0;gap:10px;border-bottom:1px solid rgba(255,255,255,.06);}
 .pay-method:last-child{border-bottom:none;}
 .pay-method .pi{width:32px;height:32px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:18px;}
 .pay-method .pi.wx{background:#07c160;}
 .pay-method .pi.ap{background:#1677ff;}
 .pay-method .pi.ap2{background:#000;color:#fff;}
 .pay-method .pn{flex:1;font-size:14px;}
 .pay-method .pr{width:18px;height:18px;border:1.5px solid rgba(255,255,255,.4);border-radius:50%;}
 .pay-method.on .pr{background:#ffd75e;border-color:#ffd75e;display:flex;align-items:center;justify-content:center;color:#000;font-size:12px;}
 .recharge-tip{font-size:11px;color:rgba(255,255,255,.5);padding:14px 18px;line-height:1.6;}
 .recharge-bottom{padding:14px 18px;background:rgba(0,0,0,.3);}

 /* === ⑦ 聊天对话 === */
 .chat-screen{display:flex;flex-direction:column;height:100%;background:#f5f5f8;}
 .chat-nav-info{display:flex;align-items:center;gap:8px;flex:1;justify-content:center;}
 .chat-nav-info .av{width:30px;height:30px;font-size:13px;}
