 .chat-nav-info .ni .st{font-size:10px;color:#4ade80;}
 .balance-bar{padding:8px 18px;background:linear-gradient(90deg,#fff5d6,#fef0f5);font-size:12px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid #f0f0f5;}
 .balance-bar .bl{color:#666;}
 .balance-bar .bl b{color:#ff9a3c;font-weight:700;}
 .balance-bar .br{color:#ff5a8a;font-weight:600;}
 .msg-flow{flex:1;overflow-y:auto;padding:14px;display:flex;flex-direction:column;gap:14px;}
