 /* ===================== 微信 H5 适配 ===================== */
 const ua = navigator.userAgent.toLowerCase()
 const isWeixin = /micromessenger/.test(ua)
 const isX5 = /mqqbrowser/.test(ua) || /tencenttraveler/.test(ua)

 // 微信浏览器禁用下拉刷新与缩放
 document.addEventListener('touchstart', function(e){
   if(e.touches.length > 1) e.preventDefault()
 },{passive:false})
 let lastTouchEnd = 0
 document.addEventListener('touchend', function(e){
   const now = Date.now()
   if(now - lastTouchEnd <= 300) e.preventDefault()
   lastTouchEnd = now
 },{passive:false})

 // 屏蔽微信内置 X5 浏览器长按菜单（图片）
 document.addEventListener('contextmenu', e => e.preventDefault())

 // 微信 JSSDK 桩（实际上线需后端签名）
 window.wxBridge = {
   ready(){ console.log('[wx] ready, isWeixin=', isWeixin) },
   shareWeChat(opts){
     if(typeof wx !== 'undefined' && wx.updateAppMessageShareData){
       wx.updateAppMessageShareData(opts)
     }else{
       console.log('[wx] share preview:', opts)
     }
   },
   pay(orderData){
     if(typeof WeixinJSBridge !== 'undefined'){
       WeixinJSBridge.invoke('getBrandWCPayRequest', orderData, res=>{
         console.log('[wx pay] result:', res)
       })
     }else{
       console.log('[wx pay] mock:', orderData)
     }
