 // ============================================================
 // EntityEngine.Demo.Lockstep — 双进程 lockstep 验收 demo
 // ============================================================
 // 跑同样确定性模拟,通过 TcpChannel 同步命令,跑完打印 World hash。
 // 两个进程的 hash 完全一致 → lockstep 链路正确。
 //
 // 用法(在两个终端):
 //   终端 A:EntityEngineDemoLockstep --host    --port 17777 --frames 200
 //   终端 B:EntityEngineDemoLockstep --client  --host 127.0.0.1 --port 17777 --peer 1 --frames 200
 //
 // 模拟规则(完全 deterministic,只依赖 frame 编号 + peer 命令):
 //   - 8 实体 / peer,共 16 entity(2 peer)
 //   - 每帧每 peer 提交一个 byte 命令 = (frame & 0xFF) ^ peerIndex
 //   - 命令值 c 用作旋转 omega 的扰动:omega' = omega + Fp(c) / 1000
 //   - 用此扰动 omega 旋转 Vel,Pos += Vel * dt
 //
 // 退出码 0 = 跑完正常退出,hash 打印到 stdout。
 // ============================================================

 using System;
 using System.Diagnostics;
 using EntityEngine.Core;
 using EntityEngine.Net;
 using EntityEngine.Render;   // 仅 host --render 时用,可选模块

 namespace EntityEngine.Demo.Lockstep;

 internal static class Program
 {
     static int Main(string[] args)
     {
         bool   isHost      = false;
         string hostAddr    = "127.0.0.1";
         int    port        = 17777;
         int    peerIndex   = 0;     // host 默认 0
         int    peerCount   = 2;     // PoC 阶段固定 2 peer
         int    frames      = 200;
         int    entitiesPerPeer = 8; // 6.1b 默认值;6.2 压测会传更大值
         bool   render      = false; // 仅 host 有效,开窗显示 entity
         bool   useUdp      = false; // PoC 3 模块 6.3:走 UdpChannel 而非 TcpChannel
         int    dropPercent = 0;     // PoC 3 模块 6.4:UDP 注入丢包率(0-100)
         int    exitAtFrame = -1;    // PoC 3 模块 6.5a:跑到 frame N 自杀,模拟掉线
         bool   rejoin     = false;  // PoC 3 模块 6.5b:重连模式
         int    lastFrame  = -1;     // PoC 3 模块 6.5b:重连时告诉 host 上次看到的帧号
         int    hashInterval = 60;   // PoC 3 模块 6.6:每 N 帧上报 World hash
         int    desyncFrame  = -1;   // PoC 3 模块 6.6:在 frame N 故意注入不一致
         int    desyncPeer   = 1;    // PoC 3 模块 6.6:注入不一致的 peer(默认 peer 1)

         for (int i = 0; i < args.Length; ++i)
         {
             switch (args[i])
             {
                 case "--host":   isHost = true; break;
                 case "--client": isHost = false; break;
                 case "--port":   port = int.Parse(args[++i]); break;
                 case "--peer":   peerIndex = int.Parse(args[++i]); break;
                 case "--peers":  peerCount = int.Parse(args[++i]); break;
                 case "--frames":           frames          = int.Parse(args[++i]); break;
                 case "--entities-per-peer":entitiesPerPeer = int.Parse(args[++i]); break;
                 case "--addr":
                 case "--host-addr":
                     hostAddr = args[++i]; break;
                 case "--render": render = true; break;
                 case "--udp":    useUdp = true; break;
                 case "--drop":   dropPercent = int.Parse(args[++i]); break;
                 case "--exit-at-frame": exitAtFrame = int.Parse(args[++i]); break;
                 case "--rejoin":    rejoin = true; break;
                 case "--last-frame": lastFrame = int.Parse(args[++i]); break;
                 case "--hash-interval": hashInterval = int.Parse(args[++i]); break;
                 case "--desync-frame":  desyncFrame  = int.Parse(args[++i]); break;
                 case "--desync-peer":   desyncPeer   = int.Parse(args[++i]); break;
                 default:
                     Console.Error.WriteLine($"unknown arg: {args[i]}");
                     return 2;
             }
         }
         if (isHost) peerIndex = 0;

         string transport = useUdp ? "udp" : "tcp";
         if (dropPercent > 0 && useUdp)
             UdpFaultInjector.DropPercent = dropPercent;
         Console.WriteLine("==========================================");
         Console.WriteLine($"  Lockstep demo  role={(isHost?"host":"client")}  peer={peerIndex}/{peerCount}  frames={frames}  entities/peer={entitiesPerPeer}  transport={transport}  drop={dropPercent}%");
         Console.WriteLine("------------------------------------------");

         IChannel channel;
         if (isHost)
         {
             if (useUdp)
             {
                 var host = new UdpChannelHost(port, peerCount);
                 Console.WriteLine($"  UDP listening on 127.0.0.1:{host.Port} ...");
                 host.WaitForPeers();
                 Console.WriteLine($"  all {peerCount} peers connected, starting lockstep");
                 channel = host;
             }
             else
             {
                 var host = new TcpChannelHost(port, peerCount);
                 Console.WriteLine($"  TCP listening on 127.0.0.1:{host.Port} ...");
                 host.WaitForPeers();
                 Console.WriteLine($"  all {peerCount} peers connected, starting lockstep");
                 channel = host;
             }
         }
         else
         {
             Console.WriteLine($"  {transport.ToUpper()} connecting to {hostAddr}:{port} as peer {peerIndex} ...");
             if (useUdp && rejoin)
             {
                 var rejoinClient = new UdpChannelClient(hostAddr, port, peerIndex, lastFrame);
                 Console.WriteLine($"  rejoin OK, replayed to frame {rejoinClient.ReplayedToFrame}");
                 channel = rejoinClient;
             }
             else
             {
                 channel = useUdp
                     ? (IChannel)new UdpChannelClient(hostAddr, port, peerIndex)
                     : new TcpChannelClient(hostAddr, port, peerIndex);
             }
             Console.WriteLine($"  connected, starting lockstep");
         }

         Renderer? renderer = null;
         if (render && isHost)
         {
             renderer = new Renderer(1280, 720,
                 $"EntityEngine lockstep — host (peers={peerCount}, total={entitiesPerPeer*peerCount})");
         }

         int catchUpToFrame = (channel is UdpChannelClient cc) ? cc.ReplayedToFrame : -1;
         ulong hash = RunSimulation(channel, peerIndex, peerCount, frames, entitiesPerPeer, renderer, exitAtFrame, catchUpToFrame, hashInterval, desyncFrame, desyncPeer);

         renderer?.Dispose();
         if (channel is IDisposable d) d.Dispose();

         Console.WriteLine($"  state hash:  0x{hash:X16}");
         Console.WriteLine("==========================================");
         return 0;
     }

     static ulong RunSimulation(IChannel channel, int peerIndex, int peerCount, int frames, int entitiesPerPeer, Renderer? renderer, int exitAtFrame, int catchUpToFrame = -1, int hashInterval = 60, int desyncFrame = -1, int desyncPeer = 1)
     {
         var runner = new LockstepRunner(channel, peerIndex, peerCount);

         using var world = new World();
         var posId = world.RegisterComponent<FpVec3>("Pos");
         var velId = world.RegisterComponent<FpVec3>("Vel");

         int totalEntities = entitiesPerPeer * peerCount;
         // 预分配 render buffer。每帧 collect 一次,避免 GC。
         var renderBuf = renderer != null ? new FpVec3[totalEntities] : null;
         // entity → owner peer 索引(用 entity raw id 做 key)。spawn 时建好。
         var ownerPeer = new System.Collections.Generic.Dictionary<ulong, int>(totalEntities);
         var entities = new Entity[totalEntities];
         for (int i = 0; i < totalEntities; ++i)
         {
             var e = world.Spawn();
             world.SetComponent(e, posId, new FpVec3(Fp.FromInt(i), Fp.Zero, Fp.Zero));
             world.SetComponent(e, velId, new FpVec3(Fp.Zero, Fp.One, Fp.Zero));
             entities[i] = e;
             ownerPeer[e.Raw] = i / entitiesPerPeer;  // entity i 属于 peer i/N
         }

         Span<ComponentId> ids = stackalloc[] { posId, velId };
         using var query = world.CreateQuery(ids);

         Fp dt    = Fp.FromInt(1) / Fp.FromInt(60);
         Fp omega = Fp.FromInt(1);
         Fp thousand = Fp.FromInt(1000);

         var sw = Stopwatch.StartNew();
         long retries = 0;

         // 6.5b:reconnect 追赶阶段 — 用 TryStepReplay 重放历史帧(不发自己的 cmd)
         if (catchUpToFrame >= 0)
         {
             Console.WriteLine($"  [rejoin] catching up frames 0..{catchUpToFrame} from replay data...");
             for (int f = 0; f <= catchUpToFrame; ++f)
             {
                 byte[][] allCmds;
                 while (!runner.TryStepReplay(f, out allCmds))
                 {
                     retries++;
                     System.Threading.Thread.Sleep(1);
                 }
                 SimulateFrame(f, peerIndex, allCmds, query, ownerPeer, dt, omega, thousand);
             }
             Console.WriteLine($"  [rejoin] catch-up complete, joining normal lockstep at frame {catchUpToFrame + 1}");
         }

         for (int f = catchUpToFrame + 1; f < frames; ++f)
         {
             // 6.5a:模拟掉线 — 跑到指定 frame 时硬退出(不优雅 dispose,
             // 模仿真实掉线场景)。其它 peer 应该在 5s 后把这个 peer 标
             // 记为 disconnected,继续推进 simulation。
             if (exitAtFrame >= 0 && f >= exitAtFrame)
             {
                 Console.Error.WriteLine($"  [peer {peerIndex}] simulating disconnect at frame {f}");
                 Environment.Exit(99);   // 不要 finally / dispose,模拟"网线被拔"
             }

             // 我的命令:byte = (frame ^ peer) & 0xff
             byte myCmd = (byte)((f ^ peerIndex) & 0xFF);
             byte[] myCmdArr = { myCmd };

             byte[][] allCmds;
             while (!runner.TryStep(f, myCmdArr, out allCmds))
             {
                 retries++;
                 System.Threading.Thread.Sleep(1);
             }

             SimulateFrame(f, peerIndex, allCmds, query, ownerPeer, dt, omega, thousand);

             // 6.6:desync 注入 — 在指定 frame 直接修改 simulation 状态,制造不一致
             if (desyncFrame >= 0 && f == desyncFrame && peerIndex == desyncPeer)
             {
                 ref FpVec3 pos0 = ref world.GetComponent<FpVec3>(entities[0], posId);
                 pos0 = new FpVec3(pos0.X + Fp.One, pos0.Y, pos0.Z);
                 Console.Error.WriteLine($"  [peer {peerIndex}] INJECTED DESYNC at frame {f} (entity[0].X += 1)");
             }

             // 6.6:周期性 hash 上报 + desync 检查
             if (f > 0 && hashInterval > 0 && f % hashInterval == 0)
             {
                 ulong currentHash = ComputeWorldHash(world, entities, posId, velId);
                 if (channel is UdpChannelClient udpClient)
                     udpClient.SendHashReport(f, currentHash);
                 else if (channel is UdpChannelHost udpHost)
+                {
                     udpHost.ReportHash(f, currentHash);
+                    for (int spin = 0; spin < 10 && !udpHost.DesyncDetected; spin++)
+                        System.Threading.Thread.Sleep(2);
+                }
             }
             // 每帧检查 desync 标志(不只在 hash check 点,因为 DESYNC_DETECTED
             // 可能在任何时刻到达)
             {
                 bool d;
                 int  df;
                 if (channel is UdpChannelClient c)      { d = c.DesyncDetected; df = c.DesyncFrame; }
                 else if (channel is UdpChannelHost host) { d = host.DesyncDetected; df = host.DesyncFrame; }
                 else { d = false; df = 0; }
                 if (d)
                 {
                     Console.Error.WriteLine($"  *** DESYNC DETECTED at frame {df}, stopping simulation ***");
                     break;
                 }
             }

             // 渲染:把所有 entity Pos collect 到 buffer 喂给 renderer
             if (renderer != null && renderBuf != null)
             {
                 if (renderer.ShouldClose) break;
                 int writeIdx = 0;
                 var iter2 = query.Iter();
                 while (iter2.Next())
                 {
                     var pos2 = iter2.GetField<FpVec3>(0);
                     pos2.CopyTo(renderBuf.AsSpan(writeIdx));
                     writeIdx += pos2.Length;
                 }
                 // worldRadius:实体最远初始位置约 totalEntities 单位(Pos.x = i)
                 float worldRadius = Math.Max(8.0f, totalEntities * 0.6f);
                 renderer.FrameBegin(worldRadius);
                 renderer.DrawPoints(renderBuf.AsSpan(0, writeIdx));
                 renderer.FrameEnd();
             }
         }
         sw.Stop();

         ulong hash = ComputeWorldHash(world, entities, posId, velId);

         Console.WriteLine($"  total time:  {sw.Elapsed.TotalMilliseconds:F1} ms ({frames} frames)");
         Console.WriteLine($"  per frame:   {sw.Elapsed.TotalMilliseconds / frames:F2} ms");
         Console.WriteLine($"  TryStep retries: {retries}");
         return hash;
     }

     /// <summary>6.6:全状态 FNV-1a hash(所有 entity 的 Pos + Vel)。</summary>
     static ulong ComputeWorldHash(World world, Entity[] entities, ComponentId posId, ComponentId velId)
     {
         ulong hash = 14695981039346656037UL;
         const ulong kFnvPrime = 1099511628211UL;
         for (int i = 0; i < entities.Length; ++i)
         {
             ref FpVec3 p = ref world.GetComponent<FpVec3>(entities[i], posId);
             ref FpVec3 v = ref world.GetComponent<FpVec3>(entities[i], velId);
             unchecked
             {
                 hash ^= (ulong)p.X.Raw; hash *= kFnvPrime;
                 hash ^= (ulong)p.Y.Raw; hash *= kFnvPrime;
                 hash ^= (ulong)p.Z.Raw; hash *= kFnvPrime;
                 hash ^= (ulong)v.X.Raw; hash *= kFnvPrime;
                 hash ^= (ulong)v.Y.Raw; hash *= kFnvPrime;
                 hash ^= (ulong)v.Z.Raw; hash *= kFnvPrime;
             }
         }
         return hash;
     }

     /// <summary>6.5b:执行一帧 deterministic 模拟(从 TryStep 回调中提取,供 catch-up 复用)。</summary>
     static void SimulateFrame(
         int frame, int peerIndex, byte[][] allCmds,
         Query query, System.Collections.Generic.Dictionary<ulong, int> ownerPeer,
         Fp dt, Fp omega, Fp thousand)
     {
         var iter = query.Iter();
         while (iter.Next())
         {
             var pos      = iter.GetField<FpVec3>(0);
             var vel      = iter.GetField<FpVec3>(1);
             var iterEnts = iter.Entities;
             int chunkN = pos.Length;
             for (int i = 0; i < chunkN; ++i)
             {
                 int owner = ownerPeer[iterEnts[i].Raw];
                 byte cmdByte = allCmds[owner].Length > 0 ? allCmds[owner][0] : (byte)0;
                 Fp pert   = Fp.FromInt(cmdByte) / thousand;
                 Fp dTheta = (omega + pert) * dt;
                 Fp cs = Fp.Cos(dTheta);
                 Fp sn = Fp.Sin(dTheta);

                 Fp vx = vel[i].X;
                 Fp vy = vel[i].Y;
                 vel[i] = new FpVec3(
                     cs * vx - sn * vy,
                     sn * vx + cs * vy,
                     vel[i].Z);
                 pos[i] = pos[i] + vel[i] * dt;
             }
         }
     }
 }
