   Button,
   Checkbox,
   Col,
   Form,
   Input,
   Modal,
   Row,
   Select,
   Space,
+  Tag,
   Tooltip,
   Typography,
   message,
   theme
 } from 'antd';
 import {
   CheckCircleFilled,
   CheckOutlined,
   DatabaseOutlined,
+  DeleteOutlined,
+  EditOutlined,
   FolderOpenOutlined,
   PlusOutlined,
   PlusCircleOutlined,
   QuestionCircleOutlined,
   SearchOutlined
 } from '@ant-design/icons';
 import { FoundryDatasetPicker } from '../../../../components/FoundryDatasetPicker';
 import { IconPicker } from '../../../../components/IconPicker';
 import { IconRenderer } from '../../../../components/IconRenderer';
 import { DATA_TYPES } from '../../../../types/ontology';
 import type {
   ActionType,
   DataType,
   ObjectType,
   PropertyDefinition
 } from '../../../../types/ontology';
 import type { FoundryDataset } from '../../../../api/foundrySources';

 interface Props {
   open: boolean;
   existingApiNames: Set<string>;
   onCancel: () => void;
   onSubmit: (object: ObjectType, actions: ActionType[]) => void;
   /** 'create'(默认) 新建对象;'edit' 编辑现有对象,数据源/元信息只读,仅可改属性 */
   mode?: 'create' | 'edit';
   /** edit 模式下的初始对象 */
   initialObject?: ObjectType | null;
 }

 type DataSourceMode = 'empty' | 'existing';

 interface MappedProp {
   source_col: string;
   source_type: string;
   nullable: boolean;
   api_name: string;
   display_name: string;
   data_type: DataType;
   description: string;
   include: boolean;
 }

 const COLORS = [
   '#4F8EF7',
   '#52C41A',
   '#FA8C16',
   '#EB2F96',
   '#722ED1',
   '#13C2C2',
   '#F5222D',
   '#FADB14'
 ];

 const STEPS = [
   { key: 'datasource', label: '数据源' },
   { key: 'metadata', label: '元信息' },
   { key: 'properties', label: '属性' },
   { key: 'actions', label: '动作' }
 ];

 function inferFoundryType(col: { name: string; type: string }): DataType {
   const t = col.type.toLowerCase();
   if (
     (col.name === 'id' || col.name.endsWith('_id')) &&
     (t === 'string' || t.startsWith('varchar'))
   )
     return 'uuid';
   if (t === 'string' || t.startsWith('varchar') || t.startsWith('char'))
     return 'string';
   if (t === 'text') return 'text';
   if (t === 'int' || t === 'bigint' || t === 'smallint' || t === 'integer')
     return 'integer';
   if (t === 'double' || t === 'float' || t.startsWith('decimal'))
     return 'float';
   if (t === 'boolean' || t === 'bool') return 'boolean';
   if (t === 'date') return 'date';
   if (t === 'datetime') return 'datetime';
   if (t === 'timestamp') return 'timestamp';
   if (t === 'json' || t === 'jsonb') return 'json';
   return 'string';
 }

 export function NewObjectModal({
   open,
   existingApiNames,
   onCancel,
   onSubmit,
   mode = 'create',
   initialObject = null
 }: Props) {
   const { token } = theme.useToken();
   const isEdit = mode === 'edit';
   const [step, setStep] = useState(0);

   const [dsMode, setDsMode] = useState<DataSourceMode>('empty');
   const [foundryDs, setFoundryDs] = useState<FoundryDataset | null>(null);
   const [pickerOpen, setPickerOpen] = useState(false);

   const [apiName, setApiName] = useState('');
   const [displayName, setDisplayName] = useState('');
   const [pluralName, setPluralName] = useState('');
   const [description, setDescription] = useState('');
   const [icon, setIcon] = useState('Box');
   const [color, setColor] = useState('#4F8EF7');
   const [group, setGroup] = useState('默认');

   const [mapped, setMapped] = useState<MappedProp[]>([]);
   const [pkProp, setPkProp] = useState<string>('');
   const [titleProp, setTitleProp] = useState<string>('');

   const [genCreate, setGenCreate] = useState(true);
   const [genUpdate, setGenUpdate] = useState(true);
   const [genDelete, setGenDelete] = useState(false);

   useEffect(() => {
     if (!open) return;
     if (isEdit && initialObject) {
       // 编辑模式直接跳到属性步,数据源/元信息只读
       setStep(2);
       setDsMode(initialObject.backing?.mode === 'existing' ? 'existing' : 'empty');
       setFoundryDs(null);
       setPickerOpen(false);
       setApiName(initialObject.api_name);
       setDisplayName(initialObject.display_name);
       setPluralName(initialObject.plural_display_name || initialObject.display_name);
       setDescription(initialObject.description ?? '');
       setIcon(initialObject.icon || 'Box');
       setColor(initialObject.color || '#4F8EF7');
       setGroup(initialObject.group_name || '默认');
       const rows: MappedProp[] = initialObject.properties
         .slice()
         .sort((a, b) => a.sort_order - b.sort_order)
         .map((p) => ({
           source_col: '',
           source_type: p.data_type,
           nullable: !p.is_required,
           api_name: p.api_name,
           display_name: p.display_name,
           data_type: p.data_type,
           description: p.description ?? '',
           include: true
         }));
       setMapped(rows);
       setPkProp(initialObject.primary_key_prop);
       setTitleProp(initialObject.title_prop);
       setGenCreate(false);
       setGenUpdate(false);
       setGenDelete(false);
       return;
     }
     setStep(0);
     setDsMode('empty');
     setFoundryDs(null);
     setPickerOpen(false);
     setApiName('');
     setDisplayName('');
     setPluralName('');
     setDescription('');
     setIcon('Box');
     setColor('#4F8EF7');
     setGroup('默认');
     setMapped([]);
     setPkProp('');
     setTitleProp('');
     setGenCreate(true);
     setGenUpdate(true);
     setGenDelete(false);
   }, [open, isEdit, initialObject]);

   useEffect(() => {
     if (!foundryDs) return;
     if (!apiName) setApiName(foundryDs.name);
     if (!displayName) setDisplayName(foundryDs.name);
     if (!pluralName) setPluralName(foundryDs.name);
     if (!description && foundryDs.description)
       setDescription(foundryDs.description);

     const rows: MappedProp[] = foundryDs.columns.map((c) => ({
       source_col: c.name,
       source_type: c.type,
       nullable: c.nullable,
       api_name: c.name,
       display_name: prettify(c.name),
       data_type: inferFoundryType(c),
       description: '',
       include: true
     }));
     setMapped(rows);

     const idCol =
       foundryDs.columns.find(
         (c) => c.name === 'id' || c.name.endsWith('_id')
       ) ?? foundryDs.columns[0];
     if (idCol) setPkProp(idCol.name);
     const titleCol =
       foundryDs.columns.find((c) =>
         ['name', 'title', 'alert_title'].includes(c.name)
       ) ?? idCol;
     if (titleCol) setTitleProp(titleCol.name);
   }, [foundryDs]);

   const includedProps = useMemo(
     () => mapped.filter((m) => m.include),
     [mapped]
   );

   const apiNameError = useMemo(() => {
     if (!apiName) return '请输入 api_name';
     if (!/^[a-z][a-z0-9_]{0,99}$/.test(apiName))
       return '英文小写开头；仅小写字母/数字/下划线';
     if (!isEdit && existingApiNames.has(apiName)) return `${apiName} 已存在`;
     return '';
   }, [apiName, existingApiNames, isEdit]);

   const stepValid: Record<number, boolean> = {
     0: true,
     1: !apiNameError && !!displayName && !!pluralName,
     2: includedProps.length > 0 ? !!pkProp && !!titleProp : true,
     3: true
   };

   const canNext = stepValid[step];

   const handleNext = () => {
     if (!isEdit && !canNext) {
       if (step === 1 && apiNameError) message.error(apiNameError);
       if (step === 2)
         message.error('请指定主键属性与标题属性');
       return;
     }
     setStep((s) => Math.min(s + 1, STEPS.length - 1));
   };

   const handleBack = () => setStep((s) => Math.max(s - 1, 0));

   const handleFinish = () => {
     if (!stepValid[1] || !stepValid[2]) {
       message.error('请先完成前面的必填项');
       return;
     }

     const properties: PropertyDefinition[] = includedProps.map((m, idx) => ({
       api_name: m.api_name,
       display_name: m.display_name || m.api_name,
       data_type: m.data_type,
       is_required: !m.nullable,
       is_array: false,
       is_indexed: m.api_name === pkProp,
       is_searchable:
         m.api_name === 'name' ||
         m.api_name.endsWith('_name') ||
         m.api_name === 'title' ||
         m.api_name.endsWith('_number'),
       enum_values: null,
       constraints: null,
       default_value: null,
       sort_order: idx,
       description: m.description?.trim() ? m.description.trim() : undefined,
       group_name: undefined
     }));

     const object: ObjectType = {
       api_name: apiName,
       display_name: displayName,
       plural_display_name: pluralName,
       description: description || undefined,
       icon,
       color,
       group_name: group,
       primary_key_prop: pkProp || (properties[0]?.api_name ?? ''),
       title_prop: titleProp || (properties[0]?.api_name ?? ''),
       backing:
         dsMode === 'existing' && foundryDs
           ? {
               mode: 'existing',
               dataset_ref: foundryDs.rid,
               dataset_path: foundryDs.path
             }
           : { mode: 'empty' },
       properties
     };

     const actions: ActionType[] = [];
     if (genCreate)
       actions.push({
         api_name: `create_${apiName}`,
         display_name: `创建 ${displayName}`,
         object_type: apiName,
         trigger_type: 'manual',
         is_active: true,
         requires_confirmation: false
       });
     if (genUpdate)
       actions.push({
         api_name: `update_${apiName}`,
         display_name: `更新 ${displayName}`,
         object_type: apiName,
         trigger_type: 'manual',
         is_active: true,
         requires_confirmation: false
       });
     if (genDelete)
       actions.push({
         api_name: `delete_${apiName}`,
         display_name: `删除 ${displayName}`,
         object_type: apiName,
         trigger_type: 'manual',
         is_active: true,
         requires_confirmation: true
       });

     onSubmit(object, actions);
   };

   return (
     <Modal
       title={isEdit ? '编辑对象' : '新建对象'}
       open={open}
       onCancel={onCancel}
       width={960}
       destroyOnClose
       styles={{ body: { padding: 0 } }}
       footer={
         <div
           style={{
             display: 'flex',
             justifyContent: 'flex-end',
             alignItems: 'center'
           }}
         >
           <Space>
             {isEdit ? (
               <>
                 {step > 0 && <Button onClick={handleBack}>上一步</Button>}
                 {step < STEPS.length - 1 && (
                   <Button onClick={handleNext}>下一步</Button>
                 )}
                 <Button onClick={onCancel}>取消</Button>
                 <Button type="primary" onClick={handleFinish}>
                   保存
                 </Button>
               </>
             ) : (
               <>
                 {step > 0 && <Button onClick={handleBack}>上一步</Button>}
                 {step < STEPS.length - 1 ? (
                   <Button
                     type="primary"
                     onClick={handleNext}
                     disabled={!canNext}
                   >
                     下一步
                   </Button>
                 ) : (
                   <Button type="primary" onClick={handleFinish}>
                     创建
                   </Button>
                 )}
               </>
             )}
           </Space>
         </div>
       }
     >
       <div style={{ display: 'flex', minHeight: 460 }}>
         {/* Vertical steps */}
         <div
           style={{
             width: 200,
             borderRight: `1px solid ${token.colorBorderSecondary}`,
             padding: '20px 12px',
             background: token.colorFillQuaternary,
             flexShrink: 0
           }}
         >
           {STEPS.map((s, idx) => {
             const active = idx === step;
             const done = idx < step;
             // edit 模式下所有步骤都可点击查看,只是 0/1 内容只读
             const clickable = isEdit
               ? true
               : idx <= step || (idx > step && stepValid[idx - 1]);
             return (
               <div
                 key={s.key}
                 onClick={() => {
                   if (isEdit) {
                     setStep(idx);
                     return;
                   }
                   if (idx <= step) setStep(idx);
                 }}
                 style={{
                   display: 'flex',
                   alignItems: 'center',
                   gap: 10,
                   padding: '8px 10px',
                   borderRadius: 4,
                   cursor: clickable ? 'pointer' : 'not-allowed',
                   background: active ? token.colorPrimaryBg : 'transparent',
                   fontWeight: active ? 600 : 400,
                   fontSize: 13,
                   color: active
                     ? token.colorPrimary
                     : done
                     ? token.colorText
                     : token.colorTextSecondary,
                   marginBottom: 2
                 }}
               >
                 <div
                   style={{
                     width: 22,
                     height: 22,
                     borderRadius: '50%',
                     display: 'flex',
                     alignItems: 'center',
                     justifyContent: 'center',
                     fontSize: 11,
                     fontWeight: 600,
                     background: active
                       ? token.colorPrimary
                       : done
                       ? token.colorSuccess
                       : token.colorFillSecondary,
                     color:
                       active || done ? '#fff' : token.colorTextSecondary
                   }}
                 >
                   {done ? <CheckOutlined /> : idx + 1}
                 </div>
                 <span>{s.label}</span>
               </div>
             );
           })}
         </div>

         {/* Main pane */}
         <div
           style={{
             flex: 1,
             padding: '24px 28px',
             minWidth: 0,
             overflow: 'auto',
             maxHeight: 560
           }}
         >
           <StepHeader index={step + 1} title={stepTitle(step)} />

           {step === 0 && (
             <DatasourceStep
               dsMode={dsMode}
               foundryDs={foundryDs}
               disabled={isEdit}
               onPickEmpty={() => {
                 setDsMode('empty');
                 setFoundryDs(null);
                 setMapped([]);
               }}
               onPickExisting={() => {
                 setDsMode('existing');
                 setPickerOpen(true);
               }}
               onChangeDs={() => setPickerOpen(true)}
             />
           )}

           {step === 1 && (
             <MetadataStep
               apiName={apiName}
               setApiName={setApiName}
               apiNameError={apiNameError}
               displayName={displayName}
               setDisplayName={setDisplayName}
               pluralName={pluralName}
               setPluralName={setPluralName}
               description={description}
               setDescription={setDescription}
               group={group}
               setGroup={setGroup}
               icon={icon}
               setIcon={setIcon}
               color={color}
               setColor={setColor}
               disabled={isEdit}
             />
           )}

           {step === 2 && (
             <PropertiesStep
               mapped={mapped}
               setMapped={setMapped}
               includedProps={includedProps}
               pkProp={pkProp}
               setPkProp={setPkProp}
               titleProp={titleProp}
               setTitleProp={setTitleProp}
               foundryName={foundryDs?.name}
             />
           )}

           {step === 3 && (
             <ActionsStep
               apiName={apiName || '<api_name>'}
               displayName={displayName || '<display_name>'}
               genCreate={genCreate}
               setGenCreate={setGenCreate}
               genUpdate={genUpdate}
               setGenUpdate={setGenUpdate}
               genDelete={genDelete}
               setGenDelete={setGenDelete}
               editMode={isEdit}
             />
           )}
         </div>
       </div>

       <FoundryDatasetPicker
         open={pickerOpen}
         onCancel={() => {
           setPickerOpen(false);
           if (!foundryDs) setDsMode('empty');
         }}
         onSelect={(d) => {
           setFoundryDs(d);
           setPickerOpen(false);
         }}
         allowedTypes={['dataset', 'pipeline_builder']}
         title="选择支撑数据集"
       />
     </Modal>
   );
 }

 function stepTitle(step: number): string {
   switch (step) {
     case 0:
       return '添加数据源';
     case 1:
       return '添加元信息';
     case 2:
       return '创建属性';
     case 3:
       return '添加动作';
     default:
       return '';
   }
 }

 function StepHeader({ index, title }: { index: number; title: string }) {
   const { token } = theme.useToken();
   return (
     <div style={{ marginBottom: 20 }}>
       <div
         style={{
           fontSize: 11,
           fontWeight: 600,
           color: token.colorTextTertiary,
           textTransform: 'uppercase',
           letterSpacing: 0.8,
           marginBottom: 4
         }}
       >
         第 {index} 步
       </div>
       <Typography.Title level={4} style={{ margin: 0 }}>
         {title}
       </Typography.Title>
     </div>
   );
 }

 function DatasourceStep({
   dsMode,
   foundryDs,
   disabled,
   onPickEmpty,
   onPickExisting,
   onChangeDs
 }: {
   dsMode: DataSourceMode;
   foundryDs: FoundryDataset | null;
   disabled?: boolean;
   onPickEmpty: () => void;
   onPickExisting: () => void;
   onChangeDs: () => void;
 }) {
   const { token } = theme.useToken();
   return (
     <div>
       {disabled && (
         <Alert
           type="info"
           showIcon
           message="编辑模式下不可修改数据源"
           style={{ marginBottom: 12 }}
         />
       )}
       <div style={{ fontSize: 13, fontWeight: 500, marginBottom: 8 }}>
         数据源
       </div>

       <div
         style={{
           display: 'grid',
           gridTemplateColumns: '1fr 1fr',
           gap: 12,
           marginBottom: 16
         }}
       >
         <DsCard
           active={dsMode === 'empty'}
           icon={<PlusOutlined />}
           title="跳过数据源"
           desc="为权限管理生成空 dataset，不存数据"
           onClick={disabled ? undefined : onPickEmpty}
         />
         <DsCard
           active={dsMode === 'existing'}
           icon={<DatabaseOutlined />}
           title="使用已有数据源"
           desc="从 Foundry 选择已存在的数据源"
           onClick={disabled ? undefined : onPickExisting}
         />
       </div>

       {dsMode === 'empty' && (
         <>
           <div
             style={{
               fontSize: 13,
               color: token.colorText,
               marginBottom: 6
             }}
           >
             选择生成空 dataset 的位置{' '}
             <Tooltip title="生成的 dataset 仅作权限载体，不存数据">
               <QuestionCircleOutlined
                 style={{
                   color: token.colorTextTertiary,
                   fontSize: 12,
                   marginLeft: 2
                 }}
               />
             </Tooltip>
           </div>
           <div
             style={{
               border: `1px solid ${token.colorBorderSecondary}`,
               borderRadius: 6,
               padding: '10px 12px',
               background: token.colorBgContainer,
               display: 'flex',
               alignItems: 'center',
               gap: 10
             }}
           >
             <SearchOutlined style={{ color: token.colorTextTertiary }} />
             <span
               style={{
                 flex: 1,
                 color: token.colorTextTertiary,
                 fontSize: 13
               }}
             >
               {foundryDs ? foundryDs.path : '尚未选择位置'}
             </span>
             <Button icon={<FolderOpenOutlined />} onClick={onChangeDs} disabled={disabled}>
               选择文件夹
             </Button>
           </div>
         </>
       )}

       {dsMode === 'existing' && (
         <>
           <div
             style={{
               fontSize: 13,
               color: token.colorText,
               marginBottom: 6
             }}
           >
             数据源
           </div>
           <div
             style={{
               border: `1px solid ${
                 foundryDs ? token.colorBorderSecondary : token.colorErrorBorder
               }`,
               borderRadius: 6,
               padding: '10px 12px',
               background: token.colorBgContainer,
               display: 'flex',
               alignItems: 'center',
               gap: 10
             }}
           >
             <FolderOpenOutlined
               style={{
                 color: foundryDs ? token.colorPrimary : token.colorTextTertiary
               }}
             />
             <div style={{ flex: 1, minWidth: 0 }}>
               {foundryDs ? (
                 <>
                   <div style={{ fontSize: 13, fontWeight: 500 }}>
                     {foundryDs.name}
                   </div>
                   <div
                     style={{
                       fontSize: 11,
                       color: token.colorTextTertiary,
                       fontFamily: 'monospace',
                       overflow: 'hidden',
                       textOverflow: 'ellipsis',
                       whiteSpace: 'nowrap'
                     }}
                   >
                     {foundryDs.path}
                   </div>
                 </>
               ) : (
                 <span style={{ color: token.colorTextTertiary, fontSize: 13 }}>
                   尚未选择数据源
                 </span>
               )}
             </div>
             <Button onClick={onChangeDs} disabled={disabled}>
               {foundryDs ? '更换' : '选择数据源'}
             </Button>
           </div>
         </>
       )}
     </div>
   );
 }

 function DsCard({
   active,
   icon,
   title,
   desc,
   onClick,
   trailing
 }: {
   active: boolean;
   icon: React.ReactNode;
   title: string;
   desc: string;
   onClick: () => void;
   trailing?: React.ReactNode;
 }) {
   const { token } = theme.useToken();
   return (
     <div
       onClick={onClick}
       style={{
         border: `1px solid ${
           active ? token.colorPrimary : token.colorBorder
         }`,
         background: active ? token.colorPrimaryBg : token.colorBgContainer,
         borderRadius: 8,
         padding: 16,
         cursor: onClick ? 'pointer' : 'default',
         position: 'relative',
         transition: 'all 0.15s'
       }}
     >
       {active && (
         <CheckCircleFilled
           style={{
             position: 'absolute',
             top: 12,
             right: 12,
             color: token.colorPrimary,
             fontSize: 18
           }}
         />
       )}
       <div
         style={{
           display: 'flex',
           alignItems: 'flex-start',
           gap: 12
         }}
       >
         <div
           style={{
             width: 32,
             height: 32,
             borderRadius: 6,
             display: 'flex',
             alignItems: 'center',
             justifyContent: 'center',
             background: active ? token.colorPrimary : token.colorFillTertiary,
             color: active ? '#fff' : token.colorTextSecondary,
             flexShrink: 0
           }}
         >
           {icon}
         </div>
         <div style={{ flex: 1, minWidth: 0 }}>
           <div
             style={{
               fontSize: 14,
               fontWeight: 600,
               color: active ? token.colorPrimary : token.colorText
             }}
           >
             {title}
           </div>
           <div
             style={{
               fontSize: 12,
               color: token.colorTextSecondary,
               lineHeight: 1.5,
               marginTop: 2
             }}
           >
             {desc}
           </div>
         </div>
       </div>
       {trailing}
     </div>
   );
 }

 function MetadataStep({
   apiName,
   setApiName,
   apiNameError,
   displayName,
   setDisplayName,
   pluralName,
   setPluralName,
   description,
   setDescription,
   group,
   setGroup,
   icon,
   setIcon,
   color,
   setColor,
   disabled
 }: {
   apiName: string;
   setApiName: (v: string) => void;
   apiNameError: string;
   displayName: string;
   setDisplayName: (v: string) => void;
   pluralName: string;
   setPluralName: (v: string) => void;
   description: string;
   setDescription: (v: string) => void;
   group: string;
   setGroup: (v: string) => void;
   icon: string;
   setIcon: (v: string) => void;
   color: string;
   setColor: (v: string) => void;
   disabled?: boolean;
 }) {
   const { token } = theme.useToken();
   return (
     <Row gutter={20}>
       <Col span={7}>
         {disabled && (
           <Alert
             type="info"
             showIcon
             message="编辑模式下不可修改元信息"
             style={{ marginBottom: 12 }}
           />
         )}
