 function suggestApiName(
   source: string,
   target: string,
   existing: Set<string>
 ): string {
   const base = `${source}_to_${target}`;
   if (!existing.has(base)) return base;
   let i = 2;
   while (existing.has(`${base}_${i}`)) i += 1;
   return `${base}_${i}`;
 }

