       reverse_display_name: reverse ? reverse : null,
       source_object_type: source.api_name,
       target_object_type: target.api_name,
       cardinality,
       description: description || undefined,
       join_method: joinMethod,
       foreign_key_property:
         joinMethod === 'foreign_key' ? fkProp : undefined,
+      target_foreign_key_property:
+        joinMethod === 'foreign_key' ? targetFkProp : undefined,
       join_table_ref:
         joinMethod === 'join_table' ? joinTableRef.trim() : undefined,
       backing_object_api_name:
         joinMethod === 'backing_object' ? backingObj : undefined
     };
     onSubmit(link);
   };

   return (
     <Modal
       title="新建关系"
       open={open}
       onCancel={onCancel}
       width={960}
       destroyOnClose
       styles={{ body: { padding: 0 } }}
       footer={
         <div
           style={{
             display: 'flex',
             justifyContent: 'space-between',
             alignItems: 'center'
           }}
         >
           <Button type="link" onClick={onCancel} style={{ padding: 0 }}>
             跳过
           </Button>
           <Space>
             {step > 0 && <Button onClick={handleBack}>上一步</Button>}
             {step < STEPS.length - 1 ? (
               <Button
                 type="primary"
                 onClick={handleNext}
                 disabled={!canNext}
               >
                 下一步
               </Button>
             ) : (
               <Button
                 type="primary"
                 onClick={handleFinish}
                 disabled={!stepValid[2]}
               >
                 创建
               </Button>
             )}
           </Space>
         </div>
       }
     >
       <div style={{ display: 'flex', minHeight: 460 }}>
         <div
           style={{
             width: 200,
             borderRight: `1px solid ${token.colorBorderSecondary}`,
             padding: '20px 12px',
             background: token.colorFillQuaternary,
             flexShrink: 0
           }}
         >
           {STEPS.map((s, idx) => {
             const active = idx === step;
             const done = idx < step;
             const clickable = idx <= step;
             return (
               <div
                 key={s.key}
                 onClick={() => {
                   if (clickable) setStep(idx);
                 }}
                 style={{
                   display: 'flex',
                   alignItems: 'center',
                   gap: 10,
                   padding: '8px 10px',
                   borderRadius: 4,
                   cursor: clickable ? 'pointer' : 'not-allowed',
                   background: active ? token.colorPrimaryBg : 'transparent',
                   fontWeight: active ? 600 : 400,
                   fontSize: 13,
                   color: active
                     ? token.colorPrimary
                     : done
                     ? token.colorText
                     : token.colorTextSecondary,
                   marginBottom: 2
                 }}
               >
                 <div
                   style={{
                     width: 22,
                     height: 22,
                     borderRadius: '50%',
                     display: 'flex',
                     alignItems: 'center',
                     justifyContent: 'center',
                     fontSize: 11,
                     fontWeight: 600,
                     background: active
                       ? token.colorPrimary
                       : done
                       ? token.colorSuccess
                       : token.colorFillSecondary,
                     color:
                       active || done ? '#fff' : token.colorTextSecondary
                   }}
                 >
                   {done ? <CheckOutlined /> : idx + 1}
                 </div>
                 <span>{s.label}</span>
               </div>
             );
           })}
         </div>

         <div
           style={{
             flex: 1,
             padding: '24px 28px',
             minWidth: 0,
             overflow: 'auto',
             maxHeight: 560
           }}
         >
           <StepHeader index={step + 1} title={stepTitle(step)} />

           {step === 0 && (
             <RelationshipStep
               cardinality={cardinality}
               setCardinality={setCardinality}
               joinMethod={joinMethod}
               setJoinMethod={setJoinMethod}
             />
           )}

           {step === 1 && (
             <ResourcesStep
               objects={objects}
               source={source}
               target={target}
               sourceApi={sourceApi}
               targetApi={targetApi}
               setSourceApi={(v) => {
                 setSourceApi(v);
                 setFkProp(undefined);
+                setTargetFkProp(undefined);
               }}
               setTargetApi={setTargetApi}
               onSwap={swapEnds}
               joinMethod={joinMethod}
               fkProp={fkProp}
               setFkProp={setFkProp}
+              targetFkProp={targetFkProp}
+              setTargetFkProp={setTargetFkProp}
               joinTableRef={joinTableRef}
               setJoinTableRef={setJoinTableRef}
               backingObj={backingObj}
               setBackingObj={setBackingObj}
+              existingPairs={existingPairs}
+              pairExists={pairExists}
             />
           )}

           {step === 2 && source && target && (
             <NamesStep
               source={source}
               target={target}
               cardinality={cardinality}
               apiName={apiName}
               setApiName={setApiName}
               apiNameError={apiNameError}
               displayName={displayName}
               setDisplayName={setDisplayName}
               reverseDisplayName={reverseDisplayName}
               setReverseDisplayName={setReverseDisplayName}
               description={description}
               setDescription={setDescription}
             />
           )}
         </div>
       </div>
     </Modal>
   );
 }

