   target,
   cardinality,
   apiName,
   setApiName,
   apiNameError,
   displayName,
   setDisplayName,
   reverseDisplayName,
   setReverseDisplayName,
   description,
   setDescription
 }: {
   source: ObjectType;
   target: ObjectType;
   cardinality: Cardinality;
   apiName: string;
   setApiName: (v: string) => void;
   apiNameError: string;
   displayName: string;
   setDisplayName: (v: string) => void;
   reverseDisplayName: string;
   setReverseDisplayName: (v: string) => void;
   description: string;
   setDescription: (v: string) => void;
 }) {
