+const CURRENT_KEY = 'starluck_current_theme';
+const DEFAULT_THEME = 'galaxy-purple';
+
+function getCurrent(){
+  return localStorage.getItem(CURRENT_KEY) || DEFAULT_THEME;
+}
+
+function setCurrent(theme){
+  localStorage.setItem(CURRENT_KEY, theme);
+  renderCurrent();
+  showToast(`已切换到「${themeLabel(theme)}」主题 · 请刷新根目录文件查看`);
+}
+
+function themeLabel(t){
+  return {'galaxy-purple':'深紫银河','warm-night':'暖夜蓝','pink-original':'粉色原版'}[t]||t;
+}
+
+function renderCurrent(){
+  const cur = getCurrent();
+  document.querySelectorAll('.theme-card').forEach(c=>{
+    const t = c.dataset.theme;
+    c.classList.toggle('current', t===cur);
+    const badge = document.getElementById('badge-'+t.split('-')[0]);
+    if(badge) badge.style.display = t===cur ? '' : 'none';
+    const btn = c.querySelector('.set-current');
+    if(btn){
+      if(t===cur){
+        btn.textContent = '✓ 当前主题';
+        btn.classList.add('is-current');
+      }else{
+        btn.textContent = '设为当前主题';
+        btn.classList.remove('is-current');
+      }
+    }
+  });
+}
+
+function showToast(msg){
+  const t = document.getElementById('toast');
+  t.textContent = msg;
+  t.classList.add('show');
+  clearTimeout(showToast._t);
+  showToast._t = setTimeout(()=>t.classList.remove('show'), 3000);
+}
+
+document.querySelectorAll('.set-current').forEach(btn=>{
+  btn.addEventListener('click', e=>{
+    e.stopPropagation();
+    const t = btn.dataset.set;
+    if(t === getCurrent()){ return; }
+    setCurrent(t);
+    btn.parentElement.parentElement.classList.add('flash');
+    setTimeout(()=>btn.parentElement.parentElement.classList.remove('flash'), 400);
+  });
+});
+
+renderCurrent();
+</script>
