+  // ============ 导出全局 API 对象 ============
+  global.starluckApi = {
+    BASE: BASE,
+    getToken: getToken,
+    setToken: setToken,
+    request: request,
+    auth: auth,
+    user: user,
+    chat: chat,
+    gift: gift,
+    payment: payment,
+    vip: vip,
+    admin: admin,
+    ws: ws
+  }
