+<!DOCTYPE html>
+<html lang="zh-CN">
+<head>
+<meta charset="UTF-8" />
+<meta name="viewport" content="width=device-width,initial-scale=1.0" />
+<title>Starluck · 三套色彩方案对比</title>
+<style>
+*{margin:0;padding:0;box-sizing:border-box;}
+html,body{font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif;background:#0a0a14;color:#e8e8f0;line-height:1.5;font-size:14px;min-height:100vh;}
+.page-hd{padding:32px 24px 20px;text-align:center;border-bottom:1px solid rgba(255,255,255,.08);}
+.page-hd h1{font-size:24px;font-weight:800;background:linear-gradient(135deg,#ffd966,#a18cff,#5a8aff);-webkit-background-clip:text;background-clip:text;color:transparent;}
+.page-hd .sub{font-size:13px;color:#8a8aa0;margin-top:6px;}
+.grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:20px;padding:24px;max-width:1500px;margin:0 auto;}
+@media(max-width:1100px){.grid{grid-template-columns:1fr;}}
+
+.option{border-radius:16px;overflow:hidden;border:1px solid rgba(255,255,255,.08);background:#12121e;}
+.option-hd{padding:16px;border-bottom:1px solid rgba(255,255,255,.06);}
+.option-hd h2{font-size:18px;font-weight:800;margin-bottom:4px;}
+.option-hd .desc{font-size:12px;color:#8a8aa0;}
+.option-hd .badge{display:inline-block;font-size:10px;padding:2px 8px;border-radius:8px;font-weight:700;margin-left:6px;vertical-align:middle;}
+.badge-rec{background:linear-gradient(135deg,#ffd966,#ff9a3c);color:#3a2a00;}
+
+/* 色卡区 */
+.swatches{display:flex;padding:12px 16px;gap:8px;flex-wrap:wrap;}
+.swatch{flex:1;min-width:60px;height:60px;border-radius:8px;display:flex;flex-direction:column;justify-content:flex-end;padding:6px;font-size:9px;font-family:monospace;color:#fff;text-shadow:0 1px 2px rgba(0,0,0,.6);}
+
+/* 预览区 */
+.preview{padding:0;position:relative;height:520px;overflow:hidden;}
+
+/* ===== 方案 A：深空蓝 + 星光金 ===== */
+.opt-a .preview{background:radial-gradient(ellipse at 20% 0%,#1a2960 0%,#0a0e2a 50%,#050817 100%);}
+.opt-a .preview::before{content:"";position:absolute;inset:0;background-image:radial-gradient(1px 1px at 20% 30%,#fff,transparent),radial-gradient(1px 1px at 60% 70%,#ffd966,transparent),radial-gradient(2px 2px at 80% 20%,#fff,transparent),radial-gradient(1px 1px at 40% 80%,#a8c4ff,transparent),radial-gradient(1px 1px at 90% 60%,#fff,transparent),radial-gradient(2px 2px at 30% 50%,#ffd966,transparent),radial-gradient(1px 1px at 70% 90%,#fff,transparent),radial-gradient(1px 1px at 10% 60%,#a8c4ff,transparent),radial-gradient(2px 2px at 50% 10%,#ffd966,transparent);background-size:300px 300px;opacity:.8;animation:twinkle 4s ease-in-out infinite;}
+
+/* ===== 方案 B：深紫 + 银河渐变 ===== */
