+.nav-item.active{color:#ff8ad4;background:linear-gradient(90deg,rgba(161,140,255,.18),transparent);font-weight:600;}
+.nav-item .num{font-size:10px;background:rgba(255,255,255,.12);width:20px;height:20px;display:inline-flex;align-items:center;justify-content:center;border-radius:50%;flex-shrink:0;}
+.sidebar-footer{padding:12px 16px;border-top:1px solid rgba(255,255,255,.08);}
+.sidebar-footer a{color:rgba(255,255,255,.4);font-size:11px;text-decoration:none;}
+
+/* 工具栏 */
+.toolbar{position:sticky;top:0;z-index:20;background:rgba(31,13,58,0.85);backdrop-filter:blur(16px);border-bottom:1px solid var(--border);padding:12px 20px;display:flex;gap:12px;align-items:center;flex-wrap:wrap;}
+.toolbar .search-box{flex:1;min-width:200px;max-width:360px;display:flex;align-items:center;background:rgba(180,140,255,.08);border:1px solid rgba(180,140,255,.18);border-radius:8px;padding:8px 12px;gap:8px;}
+.toolbar .search-box input{border:none;background:none;font-size:13px;color:var(--text);width:100%;outline:none;}
+.toolbar .search-box input::placeholder{color:var(--text3);}
+.toolbar .search-box .icon{color:var(--text3);font-size:14px;}
+.toolbar .btn-sm{padding:6px 14px;border-radius:6px;border:1px solid rgba(180,140,255,.25);background:rgba(180,140,255,.08);color:rgba(255,255,255,.85);font-size:12px;cursor:pointer;white-space:nowrap;}
+.toolbar .btn-sm:hover{background:rgba(180,140,255,.18);color:#fff;}
+.toolbar .btn-sm.active{background:var(--accent);color:#fff;border-color:var(--accent);}
+.toolbar .result-count{font-size:12px;color:var(--text3);white-space:nowrap;}
+
+/* 主内容 */
+main.content{flex:1;overflow-y:auto;min-width:0;}
+main.content::-webkit-scrollbar{width:6px;}
+main.content::-webkit-scrollbar-thumb{background:rgba(0,0,0,.15);border-radius:3px;}
+
+/* 面板容器：原型图(左) + 标注表(右) */
+.screen-section{padding:24px 20px 32px;border-bottom:1px solid var(--border);}
+.screen-section.hidden{display:none;}
+.screen-section.highlight-section{background:var(--highlight);}
+.screen-header{display:flex;align-items:center;gap:12px;margin-bottom:18px;}
+.screen-header .num-badge{width:32px;height:32px;border-radius:50%;background:linear-gradient(135deg,#a18cff,#ff8ad4);color:#fff;display:inline-flex;align-items:center;justify-content:center;font-weight:700;font-size:14px;flex-shrink:0;}
+.screen-header h2{font-size:20px;font-weight:800;color:#fff;}
+.screen-header .route{font-size:11px;color:var(--text3);background:var(--bg);padding:3px 8px;border-radius:4px;font-family:monospace;}
+.screen-panel{display:flex;gap:24px;align-items:flex-start;}
+.panel-left{width:375px;flex-shrink:0;position:sticky;top:68px;}
+
+/* 手机壳 */
+.phone-shell{width:375px;height:812px;background:rgba(180,140,255,0.06);border-radius:42px;box-shadow:0 20px 60px rgba(0,0,0,.2),0 0 0 10px #222 inset,0 0 0 14px #1a1a2e;position:relative;overflow:hidden;}
+.phone-shell::before{content:"";position:absolute;top:8px;left:50%;transform:translateX(-50%);width:120px;height:26px;background:#111;border-radius:0 0 16px 16px;z-index:100;}
+.screen-inner{width:100%;height:100%;background:linear-gradient(180deg,#1f0d3a 0%,#0a0418 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}
+
+/* 状态栏 */
+.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:12px;font-weight:600;color:#2d2d3a;flex-shrink:0;}
+.status-bar .icons{display:flex;gap:4px;align-items:center;font-size:10px;}
+.status-bar.dark{color:#fff;}
+/* 导航条 */
+.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:rgba(180,140,255,0.06);flex-shrink:0;}
+.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:20px;color:#2d2d3a;}
+.nav-bar .title{font-size:16px;font-weight:700;color:#2d2d3a;flex:1;text-align:center;}
+.nav-bar .right{min-width:32px;font-size:13px;color:#666;text-align:right;}
+/* Tab Bar */
+.tab-bar{height:58px;display:flex;background:rgba(180,140,255,0.06);border-top:1px solid rgba(255,255,255,0.06);flex-shrink:0;}
+.tab-bar .ti{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;color:#999;font-size:10px;gap:2px;}
+.tab-bar .ti .ico{font-size:20px;}
+.tab-bar .ti.active{color:#a18cff;font-weight:600;}
+/* 内容滚动区 */
+.scroll-content{flex:1;overflow-y:auto;}
+.scroll-content::-webkit-scrollbar{display:none;}
+
+/* 通用组件 */
+.btn{display:inline-flex;align-items:center;justify-content:center;height:42px;padding:0 20px;border-radius:21px;font-size:14px;font-weight:600;background:linear-gradient(135deg,#a18cff 0%,#ff8ad4 100%);color:#fff;box-shadow:0 4px 14px rgba(161,140,255,.3);cursor:default;}
+.btn.block{width:100%;}
+.btn.gold{background:linear-gradient(135deg,#ffd966,#ff9a3c);color:#5a3a00;box-shadow:0 4px 14px rgba(255,154,60,.3);}
+.btn.ghost{background:#fff;color:#a18cff;border:1.5px solid #a18cff;box-shadow:none;}
+.btn.small{height:30px;padding:0 12px;border-radius:15px;font-size:12px;}
+.av{width:44px;height:44px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:16px;}
+.av-1{background:linear-gradient(135deg,#a18cff,#ff8ad4);}
+.av-2{background:linear-gradient(135deg,#7ab5ff,#5eead4);}
+.av-3{background:linear-gradient(135deg,#ffd966,#ff9a3c);}
+.av-4{background:linear-gradient(135deg,#ff5c8a,#ffd966);}
+.av-5{background:linear-gradient(135deg,#5eead4,#7ab5ff);}
+.av-6{background:linear-gradient(135deg,#ff8ad4,#a18cff);}
+.av-7{background:linear-gradient(135deg,#ff9a3c,#ff5c8a);}
+.av-8{background:linear-gradient(135deg,#7ab5ff,#a18cff);}
+.card{background:#fff;border-radius:12px;padding:12px;box-shadow:0 4px 12px rgba(0,0,0,.04);}
+.tag{display:inline-flex;align-items:center;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:500;background:rgba(180,140,255,0.12);color:#a18cff;}
+.tag.vip{background:linear-gradient(135deg,#ffd966,#ff9a3c);color:#5a3a00;font-weight:700;}
+.tag.gold{background:#fff5d6;color:#ff9a3c;}
+.badge{display:inline-flex;align-items:center;justify-content:center;min-width:16px;height:16px;padding:0 4px;background:#ff5c8a;color:#fff;font-size:9px;font-weight:700;border-radius:8px;}
+.badge.dot{min-width:7px;height:7px;padding:0;border-radius:50%;}
+
+/* 标注面板 */
+.panel-right{flex:1;min-width:0;max-width:640px;}
+.annot-table{width:100%;border-collapse:collapse;font-size:12px;background:var(--card-bg);border-radius:10px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.04);}
+.annot-table thead{background:linear-gradient(135deg,#a18cff,#ff8ad4);color:#fff;}
+.annot-table th{padding:10px 8px;text-align:left;font-weight:600;font-size:11px;white-space:nowrap;}
+.annot-table th:first-child{width:32px;text-align:center;}
+.annot-table td{padding:8px;border-bottom:1px solid var(--border);vertical-align:top;}
+.annot-table tbody tr{cursor:default;transition:background .15s;}
+.annot-table tbody tr:hover{background:rgba(161,140,255,.06);}
+.annot-table tbody tr.row-highlight{background:rgba(161,140,255,.15)!important;outline:2px solid var(--accent);outline-offset:-2px;}
+.annot-table .el-num{text-align:center;font-weight:700;color:var(--accent);font-size:11px;width:32px;}
+.annot-table .el-name{font-weight:600;white-space:nowrap;font-size:12px;color:#fff;}
+.annot-table .el-type{font-size:10px;}
+.annot-table .el-type span{display:inline-block;padding:1px 6px;border-radius:8px;font-weight:600;}
+.el-type-btn{background:rgba(180,140,255,0.12);color:#a18cff;}
+.el-type-input{background:rgba(122,181,255,.2);color:#a8c4ff;}
+.el-type-text{background:rgba(255,255,255,.1);color:rgba(255,255,255,.7);}
+.el-type-icon{background:#0a0418;color:#7ab5ff;}
+.el-type-sel{background:rgba(94,234,212,.2);color:#5eead4;}
+.el-type-sw{background:rgba(255,217,102,.2);color:#ffd966;}
+.annot-table .el-desc{line-height:1.5;color:rgba(255,255,255,.75);}
+.annot-table .el-action{font-size:11px;color:var(--text3);line-height:1.4;}
+.annot-table .el-vip{font-size:10px;text-align:center;}
+.annot-table .vip-only{color:#ff9a3c;font-weight:700;}
+.annot-table .vip-free{color:#5eead4;}
