+          const gNodes = NODES.filter(n => n.group === grpLit);
+          const gSet = new Set(gNodes.map(n => n.id));
+          const hovSet = newId ? new Set([newId, ...(NBRS[newId]||[])]) : new Set();
+          applyHL(null, new Set([...gSet, ...hovSet]), true);
+        } else if (selId && newId && newId !== selId) {
+          const selSet = new Set([selId, ...(NBRS[selId]||[])]);
+          const hovSet = new Set([newId, ...(NBRS[newId]||[])]);
+          const merged = new Set([...selSet, ...hovSet]);
+          applyHL(selId, merged, labelsOn);
+          // Suppress labels on hover-only edges
+          eObjs.forEach(e => {
+            const inHov = hovSet.has(e.s) && hovSet.has(e.t);
+            const inSel = selSet.has(e.s) && selSet.has(e.t);
+            if (inHov && !inSel) e.eLblMat.opacity = 0;
+          });
+        } else if (selId) {
+          applyHL(selId, new Set([selId, ...(NBRS[selId]||[])]), labelsOn);
+        }
+        // grpLit without selId → do nothing, preserve group highlight
+        hovId = newId;
+        document.body.style.cursor = newId ? 'pointer' : 'default';
+      });
+      renderer.domElement.addEventListener('mouseleave', () => {
+        const selId = selRef.current;
+        const grpLit = litGrpRef.current;
+        if (!selId && !grpLit) hoverClear();
+        else if (grpLit && !selId) {
+          const gNodes = NODES.filter(n => n.group === grpLit);
+          applyHL(null, new Set(gNodes.map(n => n.id)), true);
+        } else if (selId) applyHL(selId, new Set([selId, ...(NBRS[selId]||[])]), labelsOn);
+        hovId = null; document.body.style.cursor = 'default';
+      });
+
+      // Screen-space node detection
+      const _v3 = new THREE.Vector3();
+      function nodeAtScreen(sx, sy, threshold = 13) {
+        const vW = window.innerWidth, vH = window.innerHeight;
+        let bestD = threshold, bestId = null;
+        NODES.forEach(n => {
+          _v3.set(...n.pos).project(camera);
+          if (_v3.z > 1) return;
+          const dx = (_v3.x+1)/2*vW - sx, dy = sy - (1-_v3.y)/2*vH;
+          const d = Math.sqrt(dx*dx + dy*dy);
+          if (d < bestD) { bestD = d; bestId = n.id; }
+        });
+        return bestId;
+      }
+
+      // Camera fly
+      const HOME_CAM = new THREE.Vector3(0, 60, 880), HOME_TGT = new THREE.Vector3(0, 0, 0);
+      let flyAnim = null;
+      const _startFly = (camTo, tgtTo, dur = 1100) => {
+        const sd = ctrl.dampingFactor; ctrl.dampingFactor = 1.0; ctrl.update(); ctrl.dampingFactor = sd;
+        flyAnim = { t0:performance.now(), dur, camFrom:camera.position.clone(), camTo, tgtFrom:ctrl.target.clone(), tgtTo };
+      };
+      const flyToGroup = ids => {
+        if (!ids?.length) return;
+        const pts = ids.map(id => nObjs[id]?.disc?.position).filter(Boolean);
+        if (!pts.length) return;
+        const c = new THREE.Vector3(); pts.forEach(p => c.add(p)); c.divideScalar(pts.length);
+        let maxR = 0; pts.forEach(p => { maxR = Math.max(maxR, c.distanceTo(p)); });
+        maxR = Math.max(maxR, 80); const dist = Math.max(maxR*2.1, 200);
+        _startFly(new THREE.Vector3(c.x+40, c.y+dist*0.44, c.z+dist), c.clone(), 1200);
+        ctrl.autoRotate = false;
+      };
+      const flyToHome = () => _startFly(HOME_CAM.clone(), HOME_TGT.clone(), 1400);
+
+      function isNodeInView(nid) {
+        const n = NID[nid]; if (!n) return false;
+        const v = new THREE.Vector3(...n.pos).project(camera);
+        const sx = (v.x+1)/2*W, sy = (-v.y+1)/2*H;
+        return sx >= 0 && sx <= W && sy >= 0 && sy <= H;
+      }
+
+      // Input handlers
+      let totalDrag = 0;
+      window.addEventListener('pointermove', e => { if (e.buttons > 0) totalDrag += Math.abs(e.movementX) + Math.abs(e.movementY); });
+      renderer.domElement.addEventListener('click', e => {
+        if (totalDrag > 8) return;
+        const nid = nodeAtScreen(e.clientX, e.clientY);
+        if (nid) {
+          selRef.current = nid; setSel(NID[nid]); setLitGrp(NID[nid].group);
+          labelsOn = true;
+          applyHL(nid, new Set([nid, ...(NBRS[nid]||[])]), true);
+          flyToGroup([nid, ...Array.from(NBRS[nid]||[])]);
+        } else {
+          selRef.current = null; setSel(null); setLitGrp(null); clearHL();
+        }
+      });
+      renderer.domElement.addEventListener('contextmenu', e => e.preventDefault());
+      renderer.domElement.addEventListener('pointerdown', () => { totalDrag = 0; });
+
+      // Tick
+      const clock = new THREE.Clock(); let raf;
+      const LABEL_FAR = 950, LABEL_NEAR = 450; let camDistOpacity = 0;
+      const tick = () => {
+        raf = requestAnimationFrame(tick); const T = clock.getElapsedTime();
+        if (flyAnim) {
+          const raw = Math.min((performance.now()-flyAnim.t0)/flyAnim.dur, 1);
+          const ease = raw < 0.5 ? 4*raw*raw*raw : 1-Math.pow(-2*raw+2,3)/2;
+          camera.position.lerpVectors(flyAnim.camFrom, flyAnim.camTo, ease);
+          ctrl.target.lerpVectors(flyAnim.tgtFrom, flyAnim.tgtTo, ease);
+          if (raw >= 1) flyAnim = null;
+        }
+        const camDist = camera.position.length();
+        camDistOpacity = Math.max(0, Math.min(1, (LABEL_FAR-camDist)/(LABEL_FAR-LABEL_NEAR)));
+        let sphOp;
+        if (camDist <= 300) sphOp = 0.023;
+        else if (camDist >= 1200) sphOp = 0.07;
+        else sphOp = 0.023 + (camDist-300)/(1200-300)*(0.07-0.023);
+        sphMesh.material.opacity = sphOp;
+
+        NODES.forEach(n => {
+          const o = nObjs[n.id]; if (!o) return;
+          const dist = camera.position.distanceTo(o.disc.position);
+          const wpp = (2*dist*FOV_TAN)/window.innerHeight;
+          const nodeScale = Math.min(1.2 * wpp, 1.2);    // keep sphere ~24px on screen
+          o.disc.scale.setScalar(nodeScale);
+          o.ring.scale.setScalar(nodeScale);
+          // Ring stays 2px below sphere bottom in screen space
+          o.ring.position.y = n.pos[1] - NODE_R * nodeScale - 10 * wpp;
+          const lblH = 32*wpp; o.lbl.scale.set(lblH*8.0, lblH, 1);
+          const scaledR = NODE_R * nodeScale;
+          o.lbl.position.set(n.pos[0], n.pos[1]+scaledR*1.45+lblH*0.65, n.pos[2]);
+          if (hlStates[n.id] === 'default' && n.id !== hovId) o.lbl.material.opacity = camDistOpacity;
+          if (hlStates[n.id] === 'dimmed') o.lbl.material.opacity = camDistOpacity * 0.5;
+        });
+
+        // Particle flow + line endpoints to sphere surface + arrow scaling
+        eObjs.forEach(e => {
+          const sp = nObjs[e.s]?.disc?.position, tp = nObjs[e.t]?.disc?.position;
+          if (!sp || !tp) return;
+
+          // Compute nodeScale for each end
+          const sDist = camera.position.distanceTo(sp), tDist = camera.position.distanceTo(tp);
+          const sWpp = (2*sDist*FOV_TAN)/window.innerHeight, tWpp = (2*tDist*FOV_TAN)/window.innerHeight;
+          const sNS = Math.min(1.2*sWpp, 1.2), tNS = Math.min(1.2*tWpp, 1.2);
+          const sR = NODE_R * sNS, tR = NODE_R * tNS;
+
+          // Update line endpoints to sphere surface
+          const posAttr = e.line.geometry.attributes.position;
+          posAttr.setXYZ(0, sp.x + e.dir.x * sR, sp.y + e.dir.y * sR, sp.z + e.dir.z * sR);
+          posAttr.setXYZ(1, tp.x - e.dir.x * tR, tp.y - e.dir.y * tR, tp.z - e.dir.z * tR);
+          posAttr.needsUpdate = true;
+
+          // Arrow at target end: root outside sphere, tip touches surface
+          const midD = camera.position.distanceTo(new THREE.Vector3().addVectors(sp, tp).multiplyScalar(0.5));
+          const midWpp = (2*midD*FOV_TAN)/window.innerHeight;
+          const arrScale = 2.25 * midWpp;
+          const arrowLen = 6 * arrScale;  // ConeGeometry height=6
+          e.arrT.position.set(tp.x - e.dir.x * (tR + arrowLen), tp.y - e.dir.y * (tR + arrowLen), tp.z - e.dir.z * (tR + arrowLen));
+          e.arrT.scale.setScalar(arrScale);
+          if (e.arrS) {
+            e.arrS.position.set(sp.x + e.dir.x * (sR + arrowLen), sp.y + e.dir.y * (sR + arrowLen), sp.z + e.dir.z * (sR + arrowLen));
+            e.arrS.scale.setScalar(arrScale);
+          }
+
+          // Edge label
+          const mid = new THREE.Vector3().addVectors(sp, tp).multiplyScalar(0.5);
+          if (e.eLblMat && e.eLblMat.opacity > 0.01) {
+            const lh = 22*midWpp, asp = e.eLblMat.map?._aspect||3;
+            e.eLbl.scale.set(lh*asp, lh, 1);
+          }
+
+          // Flowing particles
+          if (e.particles && e.pAttr) {
+            for (let i = 0; i < N_PARTICLES; i++) {
+              const ph = ((T * FLOW_SPEED + i / N_PARTICLES) % 1);
+              e.pAttr.setXYZ(i,
+                sp.x + (tp.x - sp.x) * ph,
+                sp.y + (tp.y - sp.y) * ph,
+                sp.z + (tp.z - sp.z) * ph
+              );
+            }
+            e.pAttr.needsUpdate = true;
+          }
+          // Reverse particles for bidirectional edges
+          if (e.revParticles && e.revPAttr) {
+            for (let i = 0; i < N_PARTICLES; i++) {
+              const ph = ((T * FLOW_SPEED + i / N_PARTICLES) % 1);
+              e.revPAttr.setXYZ(i,
+                tp.x + (sp.x - tp.x) * ph,
+                tp.y + (sp.y - tp.y) * ph,
+                tp.z + (sp.z - tp.z) * ph
+              );
+            }
+            e.revPAttr.needsUpdate = true;
+          }
+        });
+        if (window._starfield) window._starfield.rotation.y += 0.00012;
+        ctrl.update(); renderer.render(scene, camera);
+      };
+      tick();
+
+      const onResize = () => { camera.aspect = window.innerWidth/window.innerHeight; camera.updateProjectionMatrix(); renderer.setSize(window.innerWidth, window.innerHeight); };
+      window.addEventListener('resize', onResize);
+      threeRef.current = { ctrl, nObjs, eObjs, applyHL, clearHL, flyToGroup, flyToHome, hlStates };
+      window._loSceneReady = true; dismissOverlay();
+      return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', onResize); renderer.dispose(); if (el.contains(renderer.domElement)) el.removeChild(renderer.domElement); };
+    }; init(); }, []);
+
+  useEffect(() => { const { ctrl } = threeRef.current; if (ctrl) ctrl.autoRotate = rotate; }, [rotate]);
+
+  const handleGroup = group => {
+    const { applyHL, clearHL, flyToGroup, flyToHome } = threeRef.current;
+    if (!applyHL) return; setSel(null); selRef.current = null;
+    if (!group) { clearHL(); setLitGrp(null); flyToHome?.(); return; }
+    setLitGrp(group); const gNodes = NODES.filter(n => n.group === group);
+    applyHL(null, new Set(gNodes.map(n => n.id)), true); flyToGroup?.(gNodes.map(n => n.id));
+  };
+  const handleChip = node => {
+    const { applyHL, flyToGroup } = threeRef.current;
+    if (!applyHL) return; selRef.current = node.id; setSel(node); setLitGrp(node.group);
+    applyHL(node.id, new Set([node.id, ...(NBRS[node.id]||[])]), true);
+    flyToGroup?.([node.id, ...Array.from(NBRS[node.id]||[])]);
+  };
+  const handleClose = () => {
+    const { clearHL, ctrl, flyToHome } = threeRef.current;
+    selRef.current = null; setSel(null); setLitGrp(null); clearHL?.();
+    if (ctrl) ctrl.autoRotate = rotate; flyToHome?.();
+  };
+
+  return (
+    <div style={{position:'fixed',inset:0}}>
+      <div ref={mountRef} style={{position:'fixed',inset:0}}/>
+      <div id="ui">
+        <TopBar/>
+        <GroupPanel lit={litGrp} onGroup={handleGroup}/>
+        <DetailPanel node={sel} onClose={handleClose} onChipClick={handleChip}/>
+        <div className="ctrls">
+          <button className={'cbtn'+(rotate?' on':'')} onClick={() => setRotate(r=>!r)}>⟳ 自动旋转</button>
+          <button className="cbtn" onClick={handleClose}>↺ 重置</button>
+        </div>
+        <div className="hint">
+          悬浮高亮关联 · 点击节点查看关系 · 左键旋转 · 中键拖拽 · 滚轮缩放<br/>
+          左侧可按业务分组过滤
+          <div className="action-legend">
+            <div className="al-dot"/><span className="al-label">箭头方向=动作方向 · 单向箭头=1对多 · 双向箭头=多对多</span>
+          </div>
+        </div>
+      </div>
+    </div>
+  );
+};
+ReactDOM.createRoot(document.getElementById('root')).render(<App/>);
+</script>
+</body>
